export const chunk7: Poem[] = [
  { id: 770, title: "饮湖上初晴后雨",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "水光潋滟晴方好，山色空蒙雨亦奇，欲把西湖比西子，淡妆浓抹总相宜",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "饮湖上初晴后雨", original: `
水光潋滟晴方好，
山色空蒙雨亦奇，
欲把西湖比西子，
淡妆浓抹总相宜
`, translation: `晴天的时候，西湖水面波光闪闪，真好看。下雨的时候，远处山一片雾气蒙蒙，也非常奇妙。如果把美丽的西湖比作美人西施，那么不管是淡雅的妆容还是浓艳的打扮，都总是那么合适漂亮。`, interpretation: `这首诗写于苏轼在杭州做官的时候。他非常喜爱西湖，无论晴天还是雨天都去湖边游玩，还常常请朋友来喝酒聊天。诗里有两个特别美的画面：晴天时水面波光粼粼，雨天时山色云雾缭绕，各有各的妙处。最妙的是最后两句，他竟然把西湖比作中国古代四大美女之一的西施！西施不管是轻轻涂点胭脂，还是认真化上浓妆，怎么看都美，西湖也是晴天雨天都迷人。从此以后，西湖就有了一个特别好听的名字——'西子湖'，一直叫到今天呢！` }] },
  { id: 771, title: "题西林壁",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "横看成岭侧成峰，远近高低各不同，不识庐山真面目，只缘身在此山中",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "题西林壁", original: `
横看成岭侧成峰，
远近高低各不同，
不识庐山真面目，
只缘身在此山中
`, translation: `从正面看庐山，它像一座又长又宽的大山岭；从侧面看，它又变成了一座座高高的山峰。从远处、近处、高处、低处看过去，庐山的样子都不一样。我为什么认不清庐山的真正样子呢？原来是因为我自己就站在这座山里呀！`, interpretation: `这首诗写于苏轼被贬江西时，游玩庐山后题在西林寺墙壁上。那时候诗人心情虽不如意，却依然热爱观察、热爱思考。他抓住庐山「变化多端」的特点，用最朴实的语言写出了一个大道理：当局者迷，旁观者清——站在山里面，反而看不清山的全貌。这首诗最厉害的地方是「说理不说教」，读完既像在看风景，又像在听一位智者跟你聊天。后来「当局者迷，旁观者清」成了中国人最常引用的名句之一，连爸爸妈妈都常常挂在嘴边呢！` }] },
  { id: 772, title: "惠崇春江晚景",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "竹外桃花三两枝，春江水暖鸭先知，蒌蒿满地芦芽短，正是河豚欲上时",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "惠崇春江晚景", original: `
竹外桃花三两枝，
春江水暖鸭先知，
蒌蒿满地芦芽短，
正是河豚欲上时
`, translation: `竹林外边，桃花刚刚开了两三枝。春天来了，江水变暖了，最先知道的是鸭子。地面上长满了蒌蒿，芦苇也冒出了短短的新芽。这正是河豚要沿江而上的时候。`, interpretation: `这是苏轼题写在一幅画上的诗。画是和尚惠崇画的，画的是江南早春的江边景色。苏轼看完画，被画面迷住了，就写下了这首小诗。诗里最妙的是'鸭先知'三个字——鸭子整天在水里游，水是冷是暖它们最先知道，这就是'春江水暖鸭先知'。想象一下，早春的江边，竹子绿了，桃花开了，鸭子扑通扑通跳下水，多有趣呀！芦芽和蒌蒿长出来了，爱吃河豚的人就知道，又有鲜美的河豚要上市了。这首诗让我们读着读着，好像就站在春天的江边，闻到了花香，听到了鸭叫。` }] },
  { id: 773, title: "元日",
    author: "王安石",
    dynasty: "宋",
    category: "宋",
    summary: "爆竹声中一岁除，春风送暖入屠苏，千门万户曈曈日，总把新桃换旧符",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "元日", original: `
爆竹声中一岁除，
春风送暖入屠苏，
千门万户曈曈日，
总把新桃换旧符
`, translation: `在噼里啪啦的鞭炮声中，旧的一年过去了。温暖的春风把暖意送进了家家户户的屠苏酒里。初升的太阳照亮了千门万户，大家都忙着把新的桃符换下来，贴上去年的旧符。`, interpretation: `这首诗写于北宋，王安石当时正推行新法，心中充满改革理想，所以连过年都觉得充满希望。全诗围绕春节的热闹场景：爆竹、屠苏酒、桃符，都是孩子们熟悉的过年味道。'总把新桃换旧符'最有深意——表面上是说换春联，其实也象征着辞旧迎新、除旧布新。王安石用最普通的新年画面，写出了万象更新的气象，读起来喜气洋洋，是宋诗中少有的明快之作，春节时读特别应景。` }] },
  { id: 774, title: "小池",
    author: "杨万里",
    dynasty: "宋",
    category: "宋",
    summary: "泉眼无声惜细流，树阴照水爱晴柔，小荷才露尖尖角，早有蜻蜓立上头",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "小池", original: `
泉眼无声惜细流，
树阴照水爱晴柔，
小荷才露尖尖角，
早有蜻蜓立上头
`, translation: `泉眼好像很爱惜细细的泉水，悄悄地流，没有一点儿声音。岸边的树影倒映在水面，它好像也喜欢这晴天里温柔的光。一片小荷叶刚刚从水里冒出尖尖的小角，早早地就有一只蜻蜓轻轻地落在了上面。`, interpretation: `这首小诗写于南宋，杨万里是写田园诗的高手，特别擅长捕捉自然里那些小小的、有趣的瞬间。一个“惜”字、一个“爱”字，把泉水和树影都写得像有感情一样，懂得了舍不得、懂得了喜欢。画面里最有意思的是最后两句：小荷叶才露出尖尖的角，蜻蜓就抢先一步落在上面了，仿佛这两个小东西在比谁更着急呢！整首诗像一幅轻轻淡淡的水彩画，读起来让人心里也跟着安静下来，感受到夏天快要来临时的那份小期待。` }] },
  { id: 775, title: "晓出净慈寺送林子方",
    author: "杨万里",
    dynasty: "宋",
    category: "宋",
    summary: "毕竟西湖六月中，风光不与四时同，接天莲叶无穷碧，映日荷花别样红",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "晓出净慈寺送林子方", original: `
毕竟西湖六月中，
风光不与四时同，
接天莲叶无穷碧，
映日荷花别样红
`, translation: `到底是西湖的六月啊，
这里的风景和别的季节真的不一样：
碧绿的莲叶一片连着一片，一直铺到天边，望也望不到头；
红艳艳的荷花在阳光的照耀下，显得格外鲜艳好看。`, interpretation: `这首诗是宋代诗人杨万里在西湖边送别朋友林子方时写的。六月正是西湖最美的时节，诗人用“接天”的莲叶和“映日”的荷花，把夏日的西湖画成一幅又大又艳的图画：一个绿得无边无际，一个红得光彩夺目，绿和红互相映衬，美极了！这种用浓烈色彩写景的方法，是杨万里最拿手的。后人提到西湖的荷花，就会想起“接天莲叶无穷碧，映日荷花别样红”这两句，它已经成了西湖夏天最有名的一张“名片”啦！` }] },
  { id: 776, title: "宿新市徐公店",
    author: "杨万里",
    dynasty: "宋",
    category: "宋",
    summary: "篱落疏疏一径深，树头新绿未成阴，儿童急走追黄蝶，飞入菜花无处寻",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "宿新市徐公店", original: `
篱落疏疏一径深，
树头新绿未成阴，
儿童急走追黄蝶，
飞入菜花无处寻
`, translation: `稀疏的篱笆旁，有一条小路伸向远方。树枝头上新长的嫩叶还没形成浓密的树荫。小孩子飞快地跑着去追赶黄色的蝴蝶，可是蝴蝶飞进了金黄色的油菜花丛里，怎么找也找不到了。`, interpretation: `这首诗是南宋诗人杨万里晚年闲居家乡时所作，写的是他在新市徐公店住宿时看到的乡村小景。那时候他已经退休，住在乡下，最爱写田间地头的小快乐。诗里最妙的就是'黄蝶飞入菜花'——蝴蝶是黄的，油菜花也是黄的，颜色混在一起，孩子当然找不到啦！这种把眼前小事写得活灵活现的本领，就是杨万里最了不起的地方。他的诗让几百年后的小朋友读着读着，也想跑到田里去追蝴蝶呢！` }] },
  { id: 777, title: "四时田园杂兴",
    author: "范成大",
    dynasty: "宋",
    category: "宋",
    summary: "昼出耘田夜绩麻，村庄儿女各当家，童孙未解供耕织，也傍桑阴学种瓜",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "四时田园杂兴", original: `
昼出耘田夜绩麻，
村庄儿女各当家，
童孙未解供耕织，
也傍桑阴学种瓜
`, translation: `白天出去给田里除草，夜晚在家搓麻线。村里的年轻男女，各人都有自己的拿手活儿。还不明白怎么干农活的小孩儿，也学着大人的样子，挨着桑树阴凉地，试着种起小瓜来。`, interpretation: `这是南宋诗人范成大写的田园诗，当时他退休回到家乡苏州，写下六十首《四时田园杂兴》，描绘农村四季生活。诗人像一位温柔的画家，把镜头对准最普通的小村——大人忙着耕田织布，连小孩也被吸引过来。"桑阴学种瓜"是全诗最可爱的一句：小娃娃学着大人种瓜，那认真劲儿让人忍不住微笑。这首诗特别适合小朋友读，因为它告诉我们：劳动不分大小，哪怕只会"种瓜"，也是在认真生活呀！` }] },
  { id: 778, title: "四时田园杂兴·其二",
    author: "范成大",
    dynasty: "宋",
    category: "宋",
    summary: "梅子金黄杏子肥，麦花雪白菜花稀，日长篱落无人过，唯有蜻蜓蛱蝶飞",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "四时田园杂兴·其二", original: `
梅子金黄杏子肥，
麦花雪白菜花稀，
日长篱落无人过，
唯有蜻蜓蛱蝶飞
`, translation: `梅子已经金黄金黄的，杏子也长得饱满肥胖。麦田里的麦花像雪一样白，菜地里的菜花却开得稀稀疏疏。夏天白天越来越长，篱笆旁边冷冷清清没有人经过。只有蜻蜓和蝴蝶在自由自在地飞来飞去。`, interpretation: `这是南宋诗人范成大写的《四时田园杂兴》中的一首，写的是初夏江南农村的情景。那时候，范成大回到家乡苏州附近，看到田园里果子挂满枝头、庄稼长势喜人，特别开心。这首诗最厉害的地方是'对比'——一边是梅子黄、杏子肥、麦花雪白，写的是丰收在望；一边是篱笆边没人，因为农活太忙大家都下地了。诗人没写一个人，却让我们感觉处处都是勤劳的农人！'唯有蜻蜓蛱蝶飞'这句特别有名，安静中透着夏天的热闹，读完眼前好像真的看到蝴蝶在飞呢。` }] },
  { id: 779, title: "三衢道中",
    author: "曾几",
    dynasty: "宋",
    category: "宋",
    summary: "梅子黄时日日晴，小溪泛尽却山行，绿阴不减来时路，添得黄鹂四五声",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "三衢道中", original: `
梅子黄时日日晴，
小溪泛尽却山行，
绿阴不减来时路，
添得黄鹂四五声
`, translation: `梅子黄透了的时候，天天都是大晴天。我坐小船沿着溪水走到底，然后改走山路继续前行。回来的路上，绿色的树荫和来时一样浓密，还多听见了黄鹂鸟清脆的叫声，一共有四五声呢。`, interpretation: `这首诗写于南宋初年，诗人曾几从三衢山回程的路上。那时候江南正是梅雨季，难得连日放晴，诗人心情格外舒畅。全诗没有用一个华丽的字眼，却把山间初夏的清爽写得活灵活现。'绿阴不减'说明山间树木茂密，跟去时一样凉爽；'添得黄鹂四五声'是全诗最妙的一句——没说黄鹂长什么样，只说多了几声啼叫，却让人仿佛听见了那清脆的鸟鸣，闻到了夏天的味道。这种'以声写景'的写法，后来被很多诗人借鉴，成了宋诗里写山行的小名篇。` }] },
  { id: 780, title: "村晚",
    author: "雷震",
    dynasty: "宋",
    category: "宋",
    summary: "草满池塘水满陂，山衔落日浸寒漪，牧童归去横牛背，短笛无腔信口吹",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "村晚", original: `
草满池塘水满陂，
山衔落日浸寒漪，
牧童归去横牛背，
短笛无腔信口吹
`, translation: `青草长满了整个池塘，池水也涨得满满的，快要溢出堤岸。远处的山好像叼着快要落下的太阳，夕阳的倒影浸在凉凉的水波里。小牧童慢悠悠地往家走，横着身子坐在牛背上，手里拿着一支短短的笛子，也不管什么曲调，想怎么吹就怎么吹。`, interpretation: `这首诗是宋代诗人雷震写的乡村傍晚小景，南宋时期许多诗人都爱写田园生活，借美丽的乡野风光表达心中的安宁。诗人用“草满”“水满”写出夏末秋初池塘满满的生机；“山衔落日”特别有趣，把山比作一张嘴，像叼着圆圆的太阳，“浸”字让光和影子融为一体。整首诗最让人难忘的就是最后两句：小牧童横坐在牛背上，乱吹短笛，自由自在地回家。这画面一千年后读起来，还是让人觉得心里很轻松、很舒服，也成了中国古诗里最经典的童年画面之一。` }] },
  { id: 781, title: "约客",
    author: "赵师秀",
    dynasty: "宋",
    category: "宋",
    summary: "黄梅时节家家雨，青草池塘处处蛙，有约不来过夜半，闲敲棋子落灯花",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "约客", original: `
黄梅时节家家雨，
青草池塘处处蛙，
有约不来过夜半，
闲敲棋子落灯花
`, translation: `梅子黄的时候，家家户户都下着雨。青青的草地上，池塘边到处都是青蛙在叫。约好的朋友没来，等啊等，已经过了半夜。我闲着没事，就轻轻敲着棋子，看着灯芯结出的花。`, interpretation: `这首诗写于南宋，当时江南多雨，诗人赵师秀在一个梅雨夜的家里等朋友来下棋。这首小诗最妙的地方是"以闹写静"——外面雨声哗哗、青蛙呱呱，多么热闹，可屋里却只有诗人孤零零一个人，这热闹反而衬出他等人的寂寞和无聊。最后"闲敲棋子落灯花"特别有画面感，油灯快燃尽了，灯芯结成一朵朵小花，诗人百无聊赖地敲着棋子，这八个字把等待时那种又闲又闷的心情写活了。这种"等朋友没来"的小情绪，被赵师秀写得这么美，让后来很多画家都爱画这个场景呢！` }] },
  { id: 782, title: "金字经·春晚",
    author: "张可久",
    dynasty: "元",
    category: "元",
    summary: "惜花人何处落红春又残倚遍危楼十二阑弹泪痕罗袖斑江南岸夕阳山外山",
    tags: "元,写景",
    color: "#ec4899",
    sections:[    { id: 1, title: "金字经·春晚", original: `
惜花人何处？
落红春又残。
倚遍危楼十二阑。
弹泪痕罗袖斑。
江南岸，
夕阳山外山
`, translation: `爱花的人儿如今在哪里呢？花瓣纷纷飘落，春天又要过去了。我独自靠着高楼上十二道栏杆，泪珠儿滚落，把丝绸袖口都沾湿了。回头看江南岸边，夕阳正缓缓落下，远处山连着山，望也望不到头。`, interpretation: `这首小令写于元朝，那是个读书人常感到失意的年代，张可久一生做小官，漂泊江湖，词里满是他对往昔的怀念。春天本是赏花的好时候，可花瓣落了，春天要走了，爱花的人也不见了——这是他最心痛的画面。"倚遍危楼十二阑"特别动人，"十二阑"就是十二道栏杆，诗人把每一道都靠遍了，还是放不下那份思念，泪水把袖口都打湿了。最后"夕阳山外山"画面一拉远，小小的愁绪变成了天地间的大寂寞，读完让人心里也跟着空落落的。这种"以乐景写哀情"的手法，后来很多诗人都学着用了。` }] },
  { id: 783, title: "庆东原·西皋亭适兴",
    author: "薛昂夫",
    dynasty: "元",
    category: "元",
    summary: "兴为催租败欢因送酒来酒酣时诗兴依然在黄花又开朱颜未衰正好忘怀管甚谁家兴废谁成败",
    tags: "元,感怀",
    color: "#ec4899",
    sections:[    { id: 1, title: "庆东原·西皋亭适兴", original: `
兴为催租败，
欢因送酒来。
酒酣时诗兴依然在。
黄花又开，
朱颜未衰，
正好忘怀。
管甚谁家兴废谁成败
`, translation: `兴致被催租的官差搅乱了，欢快却因为有人送酒而来。喝得尽兴时写诗的兴致依然不减。菊花又一次开放，我的容颜还没有衰老，正好把一切烦恼都忘掉，管他谁家兴盛谁家衰败、谁是成功谁是失败呢！`, interpretation: `这首小令写于元代，那是汉族文人被压抑、许多人不愿做官的时代。薛昂夫曾做过官，后来辞官归隐，跑到西湖边盖了座亭子叫"西皋亭"，常和朋友们在青山绿水间喝酒写诗。曲中"催租人"一出现就把诗兴搅了，多扫兴啊！可朋友送酒一来，又高兴了。"黄花又开"是重阳节前后，暗指时光流转，"朱颜未衰"说明作者还年轻，正好把功名成败、天下兴亡都抛到一边，活得潇洒自在。这首曲语言俏皮痛快，把元代文人的洒脱劲儿写得淋漓尽致。` }] },
  { id: 784, title: "寿阳曲·山市晴岚",
    author: "马致远",
    dynasty: "元",
    category: "元",
    summary: "花村外草店西晚，霞明雨收天霁四，围山一竿残照里，锦屏风又添铺翠",
    tags: "元,写景",
    color: "#ec4899",
    sections:[    { id: 1, title: "寿阳曲·山市晴岚", original: `
花村外草店西晚，
霞明雨收天霁四，
围山一竿残照里，
锦屏风又添铺翠
`, translation: `鲜花盛开的村子外，野草铺满的小店西边，太阳快要落山了。雨停了，云散了，天空放晴，四面的青山在夕阳的余晖中显得格外明亮，就好像屏风上又添了一层翠绿的色彩。`, interpretation: `这首小令出自元代大戏剧家马致远之手，他一生写了许多描绘自然美景的小曲。元代文人常借山水寄托情怀，这首便是写雨后山村傍晚的晴朗美景。短短几句，画家一般用彩笔点染出绚烂晚霞、翠绿山峦、绚丽云霞，色彩明丽如画屏。‘锦屏风又添铺翠’最妙，把雨后青山比作锦绣屏风上又新添了一层翠绿，形象又可爱，让人读了仿佛眼前真出现一幅雨后山村图。马致远的散曲以意境清丽闻名，这首小令也让我们看到，除了著名的《天净沙·秋思》，他还能写出这样明朗动人的画面。` }] },
  { id: 785, title: "天净沙·秋",
    author: "朱庭玉",
    dynasty: "元",
    category: "元",
    summary: "庭前落尽梧桐，水边开彻芙蓉，解与诗人意同，辞柯霜叶，飞来就我题红",
    tags: "元,写景",
    color: "#ec4899",
    sections:[    { id: 1, title: "天净沙·秋", original: `
庭前落尽梧桐，
水边开彻芙蓉，
解与诗人意同，
辞柯霜叶，
飞来就我题红
`, translation: `院子里的梧桐树叶全都落光了，水边的荷花也全都开透了。它们好像懂得诗人的心情一样，一片辞别枝头的红叶，飞过来落在我的面前，等着我把诗句写在它身上呢。`, interpretation: `这首小曲写于元代，那时文人常借身边秋景诉说心曲。曲中最有趣的是“霜叶飞来求题诗”——一片红叶仿佛读懂了诗人的心意，特地飞到他身边，请求他把诗句题在上面。这正是曲中那句“解与诗人意同”的妙处：不说人惜叶，却说叶懂人，把秋天的萧瑟变成了童话般的小惊喜。写法上，短短几句由“庭前”到“水边”，再由景转到人与叶的“对话”，画面感十足。后来“题红叶”成了诗词中常见的典故，红叶传情、落叶成诗的意境便由此而来。` }] },
  { id: 786, title: "人月圆·山中书事",
    author: "张可久",
    dynasty: "元",
    category: "元",
    summary: "兴亡千古，繁华梦诗，眼倦天涯，孔林乔木，吴宫蔓草，楚庙寒鸦，数间茅舍，藏书万卷，投老村家，山中何事，松花酿酒，春水煎茶",
    tags: "元,经典",
    color: "#ec4899",
    sections:[    { id: 1, title: "人月圆·山中书事", original: `
兴亡千古，
繁华梦诗，
眼倦天涯，
孔林乔木，
吴宫蔓草，
楚庙寒鸦，
数间茅舍，
藏书万卷，
投老村家，
山中何事，
松花酿酒，
春水煎茶
`, translation: `千百年来，朝代兴亡更替，就像一场繁华的梦。双眼看遍了天下的纷扰，已经感到厌倦。孔子的墓地长满了高大的树木，吴王的宫殿爬满了野草，楚国的庙宇上落着寒冷的乌鸦。我只想回到村里，盖几间茅草屋，藏下万卷书，老了就在这里安家。山里有什么事可做呢？用松花酿酒，春天用溪水煎茶。`, interpretation: `这首小令写于元朝，那时候许多汉族文人不愿做官，隐居山林。张可久借孔子、吴王、楚国这些曾经显赫的名字，反衬功名富贵转头成空。'松花酿酒，春水煎茶'是全篇最出名的句子，把山居生活写得又雅致又舒服，读了让人也想搬进山里住。这首曲子短小精悍，对仗工整，像一幅淡雅的水墨画。` }] },
  { id: 787, title: "秋日怀弟",
    author: "谢榛",
    dynasty: "明",
    category: "明",
    summary: "生涯怜汝自樵苏，时序惊心尚道途，别后几年儿女大，望中千里弟兄孤，秋天落木愁多少，夜雨残灯梦有无",
    tags: "明,感怀",
    color: "#ef4444",
    sections:[    { id: 1, title: "秋日怀弟", original: `
生涯怜汝自樵苏，
时序惊心尚道途，
别后几年儿女大，
望中千里弟兄孤，
秋天落木愁多少，
夜雨残灯梦有无
`, translation: `我这一生最心疼的就是你啊，靠打柴割草过日子。时光飞逝让人心惊，你还在外面奔波。分别这些年，咱们的儿女都长大啦。抬头远望千里之外，只剩我一个人孤零零的兄弟。秋风吹落多少枯叶，添了无限忧愁。夜雨敲打着一盏快要熄灭的灯，梦里也不知道到底有没有见到你。`, interpretation: `这首诗是明代诗人谢榛写给远方兄弟的，充满了浓浓的思念之情。谢榛是明代文学家，他和兄弟天各一方，日子过得清苦，要靠打柴割草为生，所以一开头就心疼地说'生涯怜汝自樵苏'。诗中最让人动容的是'望中千里弟兄孤'，隔着千里路，兄弟俩一个比一个孤单。最有意境的是'秋天落木愁多少'，秋天树叶飘落，本来就让人伤感，再加上'夜雨残灯'，一个人在灯下想着亲人，梦里都盼着相见。这首诗写的是普通人对亲人的牵挂，所以特别能打动我们。` }] },
  { id: 788, title: "春词",
    author: "徐渭",
    dynasty: "明",
    category: "明",
    summary: "桃花雨过碎红飞，半逐溪流半染泥，何处飞来双燕子，一时衔在画梁西",
    tags: "明,写景",
    color: "#ef4444",
    sections:[    { id: 1, title: "春词", original: `
桃花雨过碎红飞，
半逐溪流半染泥，
何处飞来双燕子，
一时衔在画梁西
`, translation: `雨打桃花，花瓣纷纷飘落，红色的碎片四处飞舞。一半花瓣顺着溪水流走，一半却掉在泥地上，弄脏了。这时，不知从哪儿飞来了一对可爱的小燕子，它们用嘴叼起这些花瓣，飞到了屋梁西边搭窝的地方。`, interpretation: `这首诗是明代才子徐渭写的，画家出身的他特别擅长用眼睛捕捉春天的小画面。雨后落花本是很常见的景象，可徐渭偏偏观察到一半随水流、一半落泥地的细节，多有趣呀！更妙的是他笔锋一转，写燕子飞来衔花，把凋零的落花和新生的小燕子连在一起，让人觉得春天虽然有飘落，却也有新生命在忙碌。短短四句，有颜色、有声音、有动感，像一幅小动画。这首诗没有直白说春天来了，却处处是春天，正所谓'不着一字，尽得风流'，这种写法对后来写景小品影响很大呢！` }] },
  { id: 789, title: "闲居",
    author: "袁宏道",
    dynasty: "明",
    category: "明",
    summary: "翠竹青松处，桃源不记年，但看流水去，不道有人眠",
    tags: "明,经典",
    color: "#ef4444",
    sections:[    { id: 1, title: "闲居", original: `
翠竹青松处，
桃源不记年，
但看流水去，
不道有人眠
`, translation: `住在翠竹和青松围绕的地方，就像桃花源里的人一样，已经记不清外面的年号了。只看见溪水潺潺向前流去，谁也不说这里还有人安睡呢。`, interpretation: `这是明代文学家袁宏道的一首小诗。袁宏道是"公安派"的领军人物，主张文章要写出真性情，厌烦官场的束缚。这首诗写的是他归隐山林后的闲适生活。诗中最精彩的意象是"翠竹青松"和"流水"——竹子有节、松树长青、流水不停，这些都是古人心中高洁脱俗的象征。诗人把自己比作桃花源里的隐士，连时间都忘了，只管看水发呆，多么自在！全诗短短二十字，没有一个华丽的词，却让人读来心神宁静，难怪后人常说袁宏道的诗最懂"闲"的滋味。` }] },
  { id: 790, title: "渡易水",
    author: "陈子龙",
    dynasty: "明",
    category: "明",
    summary: "并刀昨夜匣中鸣，燕赵悲歌最不平，易水潺湲云草碧，可怜无处送荆卿",
    tags: "明,经典",
    color: "#ef4444",
    sections:[    { id: 1, title: "渡易水", original: `
并刀昨夜匣中鸣，
燕赵悲歌最不平，
易水潺湲云草碧，
可怜无处送荆卿
`, translation: `昨夜，并州的宝刀在刀鞘中铮铮作响，仿佛急着要出鞘。燕国赵国这片土地上，多少悲壮的歌声让人热血沸腾。易水还在潺潺流淌，岸边的云和草依旧青绿，可叹再也找不到送别荆轲的人了。`, interpretation: `这首诗写于明末，陈子龙是一个忧国忧民的大诗人，当时明朝快要灭亡了，他写这首诗来表达自己抗敌救国的心愿。诗里的'并刀'是古代著名的锋利宝刀，'荆卿'就是刺杀秦王的英雄荆轲。陈子龙借古喻今，自己就像那把急着出鞘的刀，像荆轲一样想为国出力，可身边却没有志同道合的伙伴。这首诗最妙的地方是把'刀鸣''悲歌''易水'几个画面串起来，读起来像看一场悲壮的古代电影，让人心里又激动又难过。` }] },
  { id: 791, title: "村居",
    author: "高鼎",
    dynasty: "清",
    category: "清",
    summary: "草长莺飞二月天，拂堤杨柳醉春烟，儿童散学归来早，忙趁东风放纸鸢",
    tags: "清,经典",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "村居", original: `
草长莺飞二月天，
拂堤杨柳醉春烟，
儿童散学归来早，
忙趁东风放纸鸢
`, translation: `二月里，青草长得绿油油，黄莺飞来飞去地唱着歌。河堤上的杨柳轻轻摆动，好像被春天的雾气陶醉了。小朋友们放学回来得很早，趁着东风正吹得欢，急忙跑出去放风筝。`, interpretation: `这首诗写于清朝，描绘了春天乡村孩子们放学后放风筝的快乐场景。高鼎把春天最迷人的两样东西——莺飞和杨柳，放在开头，让人一下子感到生机勃勃。'醉'字用得最妙，把杨柳拟人化了，好像它也被春光迷得沉醉。诗的后两句从风景转到人物，孩子们趁着东风放风筝，'忙趁'两个字写出孩子们争抢时间的调皮劲儿。整首诗画面感强，读起来好像能听到笑声。这首诗和《所见》《小池》一样，都是写童年乐趣的经典作品，让人想起自己小时候奔跑在田埂上的美好时光。` }] },
  { id: 792, title: "舟中",
    author: "袁枚",
    dynasty: "清",
    category: "清",
    summary: "青山若兄弟，比肩相挨倚，一峰行不到，云尽忽见水，山水方周遭，忽复见平野",
    tags: "清,写景",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "舟中", original: `
青山若兄弟，
比肩相挨倚，
一峰行不到，
云尽忽见水，
山水方周遭，
忽复见平野
`, translation: `一座座青山就像亲兄弟一样，一个挨着一个，肩并着肩地靠在一起。我乘船往前走，一座山还没走完，忽然云散了，眼前出现了流水。山啊水啊正在四周环绕着，忽然又看见了一片开阔平坦的田野。`, interpretation: `袁枚是清代的大诗人，性格喜欢自由自在，这首诗写的就是他坐船旅行时看到的风景。他把青山比作手拉手的兄弟，又把山水交映、平野突现的惊喜写得活灵活现，短短几句就像带你坐了一趟山间小船。这种边走边看、移步换景的写法，特别适合小朋友学写作文时借鉴——原来游记不用写很多字，只要抓住变化中的惊喜就够了！` }] },
  { id: 793, title: "山行杂咏",
    author: "袁枚",
    dynasty: "清",
    category: "清",
    summary: "十里崎岖半里平，一峰才送一峰迎，青山似茧将人裹，不信前头有路行",
    tags: "清,写景",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "山行杂咏", original: `
十里崎岖半里平，
一峰才送一峰迎，
青山似茧将人裹，
不信前头有路行
`, translation: `走在山路上，十里路中有八里是弯弯曲曲、高低不平的山道，只有两里稍微平坦一些。刚刚走过一座山峰，又有一座山峰迎面扑来。青山像巨大的蚕茧一样，把人紧紧地包裹起来，让人简直不敢相信前面还有路可以走。`, interpretation: `这首诗写于清代，是袁枚在山间行走时的即兴之作。诗人一生喜爱游山玩水，提倡写诗要有真性情。这首诗最有趣的地方，就是把大山比作一只巨大的蚕茧，把走路的人裹在里面，读起来又好玩又有点让人着急！这种打比方的写法叫比喻，让普通的山路一下子变得生动起来。最后一句“不信前头有路行”特别传神，山重水复疑无路的感觉跃然纸上，后来人们常用它来形容遇到困境时突然发现转机的情况。` }] },
  { id: 794, title: "西郊落花歌",
    author: "龚自珍",
    dynasty: "清",
    category: "清",
    summary: "西郊落花天下奇，古来但赋伤春诗，先生洗眼看奇景，满城车马争先时，如钱塘潮夜澎湃，如昆阳战晨披靡",
    tags: "清,写景",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "西郊落花歌", original: `
西郊落花天下奇，
古来但赋伤春诗，
先生洗眼看奇景，
满城车马争先时，
如钱塘潮夜澎湃，
如昆阳战晨披靡
`, translation: `西郊的落花景色是天下最奇特的景观，古人只写那些感伤春天逝去的诗。先生我擦亮眼睛来看这奇景，正当满城车马争相去观赏的时候。那落花像钱塘江夜晚涨潮一样汹涌澎湃，又像昆阳大战清晨敌人披靡溃散的场面。`, interpretation: `这首诗写于1839年，龚自珍辞官离开北京时。当时他已深感朝廷腐败、国家衰败，但心中仍有一股不屈的豪气。诗中最特别的是他不学古人那样为落花伤感，反而觉得这是天下奇景，要擦亮眼睛痛快地看。诗人把飞舞的落花比作钱塘江大潮的汹涌、昆阳大战的壮烈，画面感极强，读起来气势磅礴。这种化柔美为壮美的写法，让一片片飘落的花瓣都带上了英雄气概，也寄托了诗人虽落魄却不肯低头的胸怀。` }] },
  { id: 795, title: "偶成",
    author: "鲁迅",
    dynasty: "近现代",
    category: "近现代",
    summary: "文章如土欲何之，翘首东云惹梦思，所恨芳林寥落甚，春兰秋菊不同时",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "偶成", original: `
文章如土欲何之，
翘首东云惹梦思，
所恨芳林寥落甚，
春兰秋菊不同时
`, translation: `把文章看得像泥土一样低贱，又能拿它怎么办呢？我抬头望向东方的云彩，不由勾起许多思念和梦想。让人遗憾的是，芬芳的树林实在太冷清了，春天里的兰花和秋天里的菊花，怎么能同时开放呢？`, interpretation: `这首诗写于1932年，当时鲁迅身处上海，看到许多有才华的文人遭到迫害，文化界一片荒凉。诗中的“芳林”指的是文艺界，“春兰”“秋菊”比喻不同类型的优秀人才。东云和梦思寄托着鲁迅对进步文化的牵挂与向往。这首诗语言含蓄而深沉，短短四句却表达了鲁迅对当时文化环境的失望，以及对百花齐放、人才辈出的期盼。“春兰秋菊不同时”一句既写出遗憾，也暗含对未来的希望，已成为形容事物各有其时的经典名句。` }] },
  { id: 796, title: "悼杨铨",
    author: "鲁迅",
    dynasty: "近现代",
    category: "近现代",
    summary: "岂有豪情似旧时，花开花落两由之，何期泪洒江南雨，又为斯民哭健儿",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "悼杨铨", original: `
岂有豪情似旧时，
花开花落两由之，
何期泪洒江南雨，
又为斯民哭健儿
`, translation: `哪里还有从前那样奔放的豪情呢，花儿开了又落了，都随它去吧。没想到泪水竟像江南的雨一样落下，又一次为百姓失去这样一位好青年而痛哭。`, interpretation: `这首诗写于1933年，鲁迅得知友人杨铨被国民党特务暗杀后，愤然挥笔。当时白色恐怖笼罩，许多进步人士惨遭迫害。诗中“花开花落”看似淡然，实是压抑着满腔悲愤；“泪洒江南雨”化悲痛为画面，仿佛天地同悲。短短四句，把对暴行的控诉和对战友的悼念融在一起，沉痛却不消沉。鲁迅的诗一向不重华丽，这首却以最朴素的语言，写出了最深的情，被誉为现代悼亡诗中的杰作。` }] },
  { id: 797, title: "秋夜有感",
    author: "鲁迅",
    dynasty: "近现代",
    category: "近现代",
    summary: "绮罗幕后送飞光，柏树林边作夕阳，十月江南风色恶，寒鸦数点绕西兴",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "秋夜有感", original: `
绮罗幕后送飞光，
柏树林边作夕阳，
十月江南风色恶，
寒鸦数点绕西兴
`, translation: `华丽的戏台幕布后面，时光像飞一样悄悄溜走；柏树林的边上，夕阳正慢慢落下去。十月的江南啊，天气糟糕透了；几只受冻的乌鸦绕着西兴飞来飞去。`, interpretation: `这首诗写于1934年，那时鲁迅住在上海，国民党统治下社会黑暗，他的心情就像这阴冷的秋天一样沉重。诗里有几个特别有意思的画面：戏台幕后、柏树林、夕阳、寒鸦，这些都是又美又有点凄凉的景象，藏着诗人对时光白白流走、志同道合的老友渐渐离去的惋惜。写法上，鲁迅把古诗的对仗用得很巧妙，却写的是眼前实景，读起来又古又新，特别有味道。最后一句的寒鸦，成了他诗里很有名的意象，让人一读到就觉得秋意扑面而来。` }] },
  { id: 798, title: "白杨礼赞",
    author: "茅盾",
    dynasty: "近现代",
    category: "近现代",
    summary: "那是力争，上游的一，种树笔直，的干笔直，的枝参天，耸立不折，不挠对抗，着西北风",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "白杨礼赞", original: `
（版权保护作品，
此处仅展示片段供教学参考）那是力争，
上游的一，
种树笔直，
的干...
`, translation: `那是努力向上生长的树，笔直的树干……`, interpretation: `这是茅盾先生写于1941年的散文名篇。那时候抗日战争正激烈，许多人离开家乡去往西北大后方。茅盾先生在西北高原上看到一排排白杨树，它们笔直地立在风沙里，不弯腰、不低头，就像守卫家乡的战士。于是他写下了这篇文章，把白杨树比作北方的农民、守卫祖国的士兵。'力争上游'这四个字特别有名，意思是永远不满足，要往更高更强的地方努力。现在我们说一个人'力争上游'，就是从这里来的。` }] },
  { id: 799, title: "黄昏",
    author: "陈然",
    dynasty: "近现代",
    category: "近现代",
    summary: "任脚下响着沉重的铁镣任你把皮鞭举得高高我不需要什么自由哪怕胸口对着带血的刺刀",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "黄昏", original: `
任脚下响着沉重的铁镣，
任你把皮鞭举得高高，
我不需要什么自由，
哪怕胸口对着带血的刺刀
`, translation: `就算脚上戴着沉重的铁镣，哪怕发出响亮的声音，我也不在乎。就算你把皮鞭高高举起，我也一点都不害怕。我不需要别人施舍给我的自由，哪怕胸口正对着那把沾着鲜血的刺刀。`, interpretation: `这首诗写于1949年前后，革命烈士陈然在狱中面对敌人的严刑拷打，依然坚贞不屈。诗中的“铁镣”“皮鞭”“刺刀”是黑暗势力的象征，而诗人用坚定的口吻告诉敌人：真正的自由不是你们能给的，也绝不是靠低头求饶换来的。整首诗语言铿锵有力，像战士的宣言，展现了共产党人宁死不屈的大无畏精神。后来这首诗被谱成《我的自白书》广为传唱，成为革命文学中的经典篇章，激励了一代又一代人。` }] },
  { id: 800, title: "七律·和柳亚子先生（节选）",
    author: "毛泽东",
    dynasty: "近现代",
    category: "近现代",
    summary: "牢骚太盛防肠断，风物长宜放眼量，莫道昆明池水浅，观鱼胜过富春江",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "七律·和柳亚子先生（节选）", original: `
（版权保护作品，
此处仅展示片段供教学参考）饮茶粤海未能忘，
索句渝州叶正黄，
三十...
`, translation: `我们在广州一起喝茶的情景，我到现在都还记得清清楚楚。向你请教诗句是在重庆，那时候正是秋天，树叶变黄的时候。算一算，我们认识已经三十一年啦。`, interpretation: `这首诗写于1949年新中国成立前夕，毛泽东与老朋友柳亚子在多年的交往中建立了深厚情谊。诗中通过“粤海饮茶”“渝州索句”两个具体场景，把读者带回那些一起品茶论诗的温暖时光。短短几句，没有华丽的词藻，却用最朴素的语言道出了真友情——即使相隔千里、历经风雨，心里依然惦记着对方。诗的语言像说话一样自然，读来亲切感人，也让小朋友们明白：真正的朋友，是哪怕分开很久，想起时心里也是暖的。` }] },
  { id: 801, title: "水调歌头·游泳（节选）",
    author: "毛泽东",
    dynasty: "近现代",
    category: "近现代",
    summary: "万里长江横渡极，目楚天舒不管风，吹浪打胜似闲庭，信步今日得宽馀",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "水调歌头·游泳（节选）", original: `
（版权保护作品，
此处仅展示片段供教学参考）才饮长沙水，
又食武昌鱼，
万里长江横渡...
`, translation: `刚喝了长沙的清甜井水，又品尝了武昌鲜美的鱼。我畅游在浩浩荡荡的万里长江之上……`, interpretation: `这首词写于1956年5月，毛泽东畅游长江之后，豪情满怀。词中用“长沙水”“武昌鱼”这些亲切的家乡美食来串联行程，画面感十足，仿佛一场说走就走的旅行。短短几行就写出了从湖南到湖北、飞跃万里的气魄，充满了革命家的浪漫与乐观。后人常引用“才饮长沙水，又食武昌鱼”来形容行踪的潇洒和心情的畅快，是一首既亲切又磅礴的现代经典词作。` }] },
  { id: 802, title: "清平乐·六盘山",
    author: "毛泽东",
    dynasty: "近现代",
    category: "近现代",
    summary: "天高云淡，望断南飞雁，不到长城非好汉，屈指行程二万，六盘山上高峰，红旗漫卷西风，今日长缨在手，何时缚住苍龙",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "清平乐·六盘山", original: `
（版权保护作品，
此处仅展示片段供教学参考）不到长城非好汉
`, translation: `不到长城，就不算真正的好汉！长征的路上，战士们翻过高山，趟过大河，吃过草根，咽过树皮，但从来没有人喊苦叫累。因为大家心里都憋着一股劲儿：一定要走到长城边！`, interpretation: `这首词写于1935年10月，毛主席带领红军长征翻越最后一座大山——六盘山时。长征路上红军走了二万五千里，历经千辛万苦，很多人牺牲在了路上。'不到长城非好汉'是整首词最有名的一句，用咱们熟悉的'好汉'打比方，说没有走到胜利的地方就不是真正的英雄，激励战士们咬牙坚持。这句话现在常被引用，意思是要做成一件事，就得坚持到底，不能半途而废。` }] },
  { id: 803, title: "忆秦娥·娄山关（节选）",
    author: "毛泽东",
    dynasty: "近现代",
    category: "近现代",
    summary: "雄关漫道真，如铁而今迈，步从头越从，头越苍山如，海残阳如血",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "忆秦娥·娄山关（节选）", original: `
（版权保护作品，
此处仅展示片段供教学参考）西风烈长空雁叫霜晨月霜晨月马蹄声碎喇叭声...
`, translation: `西风猛烈地吹着，长空中大雁鸣叫，在结霜的清晨里，一轮冷月挂在天上。在这寒冷的清晨，骑兵的马蹄声细碎急促，部队的喇叭声低沉呜咽。`, interpretation: `这首词写于1935年长征途中，是毛泽东率领红军第二次攻克贵州娄山关后所作。当时红军处境艰难，战士们跋山涉水、昼夜行军，前方有敌军堵截，后方有追兵紧逼。词中'西风''长雁''霜月''马蹄''喇叭'几个意象，营造出苍凉、悲壮又激昂的氛围。短短几句，既有清晨行军的紧张画面，又有战士们不畏艰险的豪情。后两句'雄关漫道真如铁，而今迈步从头越'更是千古名句，激励了一代又一代人面对困难时奋勇向前、永不言败的精神。` }] },
  { id: 804, title: "梅岭三章（节选）",
    author: "陈毅",
    dynasty: "近现代",
    category: "近现代",
    summary: "此去泉台招旧部，旌旗十万斩阎罗，南国烽烟正十年，此头须向国门悬，后死诸君多努力，捷报飞来当纸钱",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "梅岭三章（节选）", original: `
（版权保护作品，
此处仅展示片段供教学参考）断头今日意如何，
创业艰难百战多，
此去...
`, translation: `今天就要牺牲了，我的心意是怎样的呢？回想过去，革命事业经历了许多艰难，打了很多仗。

此去……（后续内容因版本或教学节选暂未展示）`, interpretation: `这是陈毅将军在1936年梅山被敌人围困、生命危在旦夕时写下的三首诗。当时他身负重伤，藏在草丛里，以为自己必死无疑，却依然豪情满怀。

诗中最动人的就是第一句——"断头今日意如何"，面对死亡，他不悲不惧，反而冷静地思考起来。"创业艰难百战多"说的是过去的革命斗争多么不容易。整首诗把视死如归的英雄气概写得像说话一样自然，没有华丽的辞藻，却字字千钧。

这种在生死关头依然想着革命事业的精神，特别让人敬佩。后来"断头今日意如何"成了名句，提醒我们：真正的勇敢，不是不怕死，而是知道为什么而活。` }] },
  { id: 805, title: "赠友人",
    author: "朱德",
    dynasty: "近现代",
    category: "近现代",
    summary: "北华收复赖群雄，猛士如云唱大风，自信挥戈能退日，河山依旧战旗红",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "赠友人", original: `
（版权保护作品，
此处仅展示片段供教学参考）北华收复赖群雄，
猛士如云唱大风，
自信...
`, translation: `收复北华靠的是英雄豪杰们，勇猛的战士们像云一样聚拢，高唱着胜利的歌曲。大家都充满自信……`, interpretation: `这首诗是朱德元帅在抗战时期写的。北华指的是华北地区，当时被日本侵略者占领。诗人告诉我们，打仗光靠一个人可不行，得靠大家一起努力，就像云一样多的英雄好汉团结起来，才能把敌人赶走！诗里“猛士如云”这个比喻特别形象，读起来让人热血沸腾，觉得咱们中国人团结起来力量大得很。这首诗也鼓励小朋友们，做事也要有自信，和小伙伴们一起合作，什么困难都不怕！` }] },
  { id: 806, title: "游七星岩",
    author: "叶剑英",
    dynasty: "近现代",
    category: "近现代",
    summary: "借得西湖水一环，更移阳朔七堆山，堤边添上丝丝柳，画幅长留天地间",
    tags: "近现代,写景",
    color: "#64748b",
    sections:[    { id: 1, title: "游七星岩", original: `
（版权保护作品，
此处仅展示片段供教学参考）借得西湖水一环，
更移阳朔七堆山，
堤边...
`, translation: `借来西湖的一弯湖水，又搬来阳朔的七座小山。湖边新修的长堤上，添上几座小桥点缀其间，让这七星岩的美景更迷人了。`, interpretation: `这首诗写于20世纪60年代，叶剑英元帅游览广西桂林七星岩时所作。当时他已是国家领导人，但诗中却充满童趣，像是在玩"搬家游戏"——把杭州西湖的水和桂林阳朔的山都借来装点七星岩。诗人用"借"和"移"两个动词，把美景写得活灵活现，足见他对祖国山水的热爱。这首诗的巧妙之处在于，把桂林的山水和杭州、阳朔的名胜放在一起比较，让小朋友们明白：原来我们中国的好风景，各有各的妙处，连大诗人都想把它们都收进一个园子里呢！` }] },
  { id: 807, title: "远望",
    author: "叶剑英",
    dynasty: "近现代",
    category: "近现代",
    summary: "忧患元元忆逝翁，红旗缥缈没遥空，昏鸦三匝迷枯树，回雁兼程溯旧踪，赤道雕弓能射虎，椰林匕首敢屠龙，景升父子皆豚犬，旋转还凭革命功",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "远望", original: `
（版权保护作品，
此处仅展示片段供教学参考）忧患元元忆逝翁，
红旗缥缈没遥空，
昏鸦...
`, translation: `革命前辈啊，你曾为人民的苦难日夜忧心。
如今红旗虽已升起，却仿佛在遥远的天空中隐隐飘动。
黄昏的乌鸦啊，遮住了苍茫的天地。`, interpretation: `这首诗写于1965年，叶剑英登上北方某山，眺望远方，心中涌起对毛泽东等老一辈革命家的深深怀念。当时新中国已走过十六年，但诗人看到暮色中乌鸦乱飞、红旗隐于天际的景象，忧虑国家可能出现的危机。后来“文化大革命”果然发生，证明诗人的远见卓识。诗中“红旗缥缈”“昏鸦乱飞”的对比，藏着深深的忧国情怀。最难得的是，叶帅在欢乐年代能听出时代的隐忧，正是这种“先天下之忧而忧”的气魄，让这首诗成为革命领袖诗中的经典名篇。` }] },
  { id: 808, title: "无题",
    author: "鲁迅",
    dynasty: "近现代",
    category: "近现代",
    summary: "血沃中原肥劲草，寒凝大地发春华，英雄多故谋夫病，泪洒崇陵噪暮鸦",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "无题", original: `
血沃中原肥劲草，
寒凝大地发春华，
英雄多故谋夫病，
泪洒崇陵噪暮鸦
`, translation: `烈士的鲜血浇灌了中原大地，让坚强的野草长得更加茂盛。寒冷虽然冻结了整个世界，但到了春天依然会开出美丽的花朵。虽然英雄很多但许多人已经牺牲，留下来的谋士也病倒了。只剩下泪水洒在中山陵旁的松柏上，傍晚的乌鸦在那里呱呱乱叫。`, interpretation: `这首诗写于1932年，当时日本侵略中国，国民党却不抵抗，鲁迅非常愤怒又难过。诗里有两个特别重要的对比：热血浇灌土地长出青草，严寒封锁大地却挡不住春花开放——这是说反动派越残害革命者，革命力量反而越强大！诗的最后一句最让人心酸，眼泪落在孙中山先生的陵墓旁，连乌鸦的叫声都显得凄凉。鲁迅用短短四句话，既写出了对牺牲战友的痛心，也表达了对未来的信心。这两句'血沃中原肥劲草，寒凝大地发春华'成了名言，被很多人引用，激励人们在困难中看到希望。` }] },
  { id: 809, title: "答客诮",
    author: "鲁迅",
    dynasty: "近现代",
    category: "近现代",
    summary: "无情未必真豪杰，怜子如何不丈夫，知否兴风狂啸者，回眸时看小於菟",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "答客诮", original: `
无情未必真豪杰，
怜子如何不丈夫，
知否兴风狂啸者，
回眸时看小於菟
`, translation: `没有冷酷无情的人未必就是真正的大英雄，疼爱孩子的又怎么能说不是大丈夫呢？你知道吗，那些能呼风唤雨、威风凛凛的猛虎，也会回头温柔地看看自己的小虎崽呢。`, interpretation: `这首诗写于1931年，当时鲁迅先生常收到朋友来信，劝他不要太溺爱孩子。于是他写下这首小诗作为回应。诗中最妙的是「小於菟」这个意象，「於菟」是古汉语里老虎的意思，鲁迅用「大老虎也会疼小老虎」来打比方，特别生动有趣。这首诗告诉我们：真正勇敢的人，恰恰也有柔软的一面，爱孩子和当大英雄从来都不矛盾。短短四句，既是对朋友的回答，也是鲁迅对父爱的温柔宣言。` }] },
  { id: 810, title: "惯于长夜过春时",
    author: "鲁迅",
    dynasty: "近现代",
    category: "近现代",
    summary: "惯于长夜过春时挈妇将雏鬓有丝梦里依稀慈母泪城头变幻大王旗忍看朋辈成新怒向刀丛觅小诗",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "惯于长夜过春时", original: `
惯于长夜过春时，
挈妇将雏鬓有丝，
梦里依稀慈母泪，
城头变幻大王旗，
忍看朋辈成新鬼，
怒向刀丛觅小诗
`, translation: `我已经习惯了在漫长的黑夜里度过春天，带着妻子和孩子们一起逃难，两鬓已经悄悄长出了白发。睡梦中隐隐约约看见慈祥的母亲在为我流泪，城头上各种军阀的旗帜不停地变换。今天听到好朋友被害死的消息，我强忍着悲痛，愤怒地在这刀枪丛中寻找机会写下一首小诗。`, interpretation: `这首诗写于1931年，当时鲁迅得知柔石等左翼青年被国民党反动派杀害，悲愤中挥笔写成。诗中“长夜”象征黑暗的旧社会，“春时”却暗示着对光明的期待，春天本应美好，却只能在逃亡中度过，反差强烈。“城头变幻大王旗”一句特别形象，把军阀混战、你方唱罢我登场的丑态刻画得入木三分，是流传很广的名句。整首诗语言凝练有力，情感深沉悲愤，体现出鲁迅作为一位硬骨头文人，在白色恐怖中依然不屈不挠、敢于斗争的精神。` }] },
  { id: 811, title: "少年行",
    author: "郭沫若",
    dynasty: "近现代",
    category: "近现代",
    summary: "少年负志，气海运期，鲲鹏杖策，渡东海归，来气蒸云，梦吞八九",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "少年行", original: `
（版权保护作品，
此处仅展示片段供教学参考）少年负志，
气海运期，
鲲鹏杖策，
渡东...
`, translation: `少年郎呀心怀壮志，胸怀像大海一样宽广，希望能乘着时代的风展翅高飞。我拄着拐杖策马前行，一路向东而去……`, interpretation: `这首诗写于近现代，正是中华民族觉醒、青年们立志报国的时代。郭沫若是著名的诗人、学者，他笔下的“少年”充满朝气与抱负。诗中最精彩的意象是“鲲鹏”——这是《庄子》里的大鸟，能扶摇直上九万里，象征着少年远大的理想。而“杖策渡东”则化用典故，写出少年拄着拐杖也要奔向远方的决心。这首诗语言铿锵有力，节奏明快，读起来像在听一位热血少年在宣誓，非常适合作为孩子们立志的座右铭。` }] },
  { id: 812, title: "礁石",
    author: "艾青",
    dynasty: "近现代",
    category: "近现代",
    summary: "一个浪一个浪无休止地扑过来每一个浪都在它脚下被打成碎沫散开它的脸上和身上像刀砍过的一样但它依然站在那里含着微笑看着海洋",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "礁石", original: `
（版权保护作品，
此处仅展示片段供教学参考）一个浪一个浪无休止地扑过来每一个浪都在它...
`, translation: `一个浪接着一个浪，不停地扑打过来。每一个浪打在礁石上，又都碎成了一片片浪花。礁石站在那里，脸上满是海浪留下的伤疤和坑洞，但它依然挺立着，看着大海。浪花扑过来，笑着，又跑开了。礁石在浪花的笑声中沉默着。可是它依然站在那里，脸上带着深深的皱纹，像在笑，又像在思考。`, interpretation: `这首诗写于1954年，艾青借礁石表达了一种不屈服的力量。礁石是诗中最核心的意象——它被海浪一次次撞击，浑身是伤，却始终挺立不倒。海浪象征着生活中的挫折和压力，而礁石的沉默与坚持，正是艾青想告诉孩子们的：在困难面前，不必慌张，也不用喊叫，只要稳稳地站在那里，就是最大的勇敢。这首诗最打动人的，就是那句'它的脸上和身上／像刀砍过的一样／但它依然站在那里／含着微笑，看着海洋'，简短却有力，后来成为无数人面对逆境时的座右铭。` }] },
  { id: 813, title: "我爱这土地（节选）",
    author: "艾青",
    dynasty: "近现代",
    category: "近现代",
    summary: "为什么我的眼里常含泪水因为我对这土地爱得深沉",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "我爱这土地（节选）", original: `
（版权保护作品，
此处仅展示片段供教学参考）假如我是一只鸟我也应该用嘶哑的喉咙歌唱为...
`, translation: `假如我是一只小鸟，我也应该用已经沙哑的嗓子不停地歌唱——直到自己死去。这土地被风雨打击着，河流也哀叹着，激怒的风正吹向那来自林间的无比温柔与宁静……`, interpretation: `这首诗写于抗战时期，艾青面对苦难深重的祖国，悲愤而深沉。诗人自比一只小鸟，哪怕嗓子沙哑也要拼命歌唱，体现的是一种至死不渝的爱国情怀。核心意象是“鸟”，它不是快乐的百灵，而是嘶哑的、带血而啼的鸟，代表着在苦难中挣扎却永不放弃的人民。诗中“嘶哑的喉咙歌唱”一句尤为动人——嘶哑是因为喊得太多、哭得太多，却依然要唱，这种悲壮感人至深。这首诗影响了无数中国人，是现代诗歌中爱国主题的经典之作。` }] },
  { id: 814, title: "纸船",
    author: "冰心",
    dynasty: "近现代",
    category: "近现代",
    summary: "我从不肯妄，弃了一张纸，总是留着留，着叠成一只，一只很小的，船儿从舟上，抛下在海里，有的被天风，吹卷到舟中，的窗里有的，被海浪打湿，沾在船头上",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "纸船", original: `
（版权保护作品，
此处仅展示片段供教学参考）我从不肯妄，
弃了一张纸，
总是留着留\...
`, translation: `我从不肯随便扔掉一张纸，总是把纸留着、留着，叠成一只只小小的船，从船上抛到海里。有的船被风吹到了岸边，有的被海浪打湿了太阳，我也顾不上去管它。`, interpretation: `这首诗写于1923年，冰心去美国留学时，乘坐邮轮在太平洋上航行，想念远方的妈妈，于是每天叠一只纸船扔进大海，寄托对母亲的思念。诗里最动人的就是"纸船"这个意象——小小的纸船叠着的是女儿的爱，漂得再远，也带着妈妈的心愿。冰心用孩子般的口吻说话，特别适合小朋友读，因为她的诗就像在和你聊天一样亲切。这首《纸船》后来成了游子思乡念母的经典名篇，也让"母亲"成为冰心笔下最温暖的主题。` }] },
  { id: 815, title: "成功的花",
    author: "冰心",
    dynasty: "近现代",
    category: "近现代",
    summary: "成功的花人们只惊羡她现时的明艳然而当初她的芽儿浸透了奋斗的泪泉洒遍了牺牲的血雨",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "成功的花", original: `
（版权保护作品，
此处仅展示片段供教学参考）成功的花人们只惊羡她现时的明艳然而当初她...
`, translation: `成功的花，人们只惊羡她现在绽放得多么鲜艳夺目。可是当初，她的芽儿浸透了奋斗的泪水，洒遍了牺牲的鲜血。`, interpretation: `这首小诗写于二十世纪二十年代，冰心用花来比喻成功的人。她想告诉小朋友：别只看到别人成功时光彩照人的样子，那背后藏着许多辛苦和付出。诗里'泪水'和'鲜血'不是真的流血，而是说为了目标要努力、流汗，甚至做出牺牲。冰心用短短几句话，把'台上一分钟，台下十年功'的道理说得特别生动。这首诗被选进课本，鼓励了一代又一代的孩子：要不怕吃苦，才能开出自己的花。` }] },
  { id: 816, title: "枫桥夜泊",
    author: "张继",
    dynasty: "唐",
    category: "唐",
    summary: "月落乌啼霜满天，江枫渔火对愁眠，姑苏城外寒山寺，夜半钟声到客船",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "枫桥夜泊", original: `
月落乌啼霜满天，
江枫渔火对愁眠，
姑苏城外寒山寺，
夜半钟声到客船
`, translation: `月亮慢慢落下去，乌鸦偶尔叫几声，霜气冷得好像布满了整个天空。江边的枫树和渔船上的灯火，伴着我这个满心忧愁的人入睡。苏州城外那座有名的寒山寺，半夜敲响的钟声悠悠地传到了我坐的小船上。`, interpretation: `这首诗写于安史之乱后，张继逃难来到江南，夜里停船在苏州枫桥，孤独和忧愁涌上心头。诗里有几个特别美的画面：月亮落下、乌鸦啼叫、满天白霜、江边枫树、渔船灯火、寺院钟声，这些都是秋天夜晚独有的景象。整首诗最厉害的地方是最后一句——明明是写声音，却让我们仿佛看到了一个很静很静的夜晚，这就是常说的“闹中取静”。从此，“姑苏城外寒山寺”成了人人向往的地方，连日本朋友都知道寒山寺呢！` }] },
  { id: 817, title: "出塞",
    author: "王昌龄",
    dynasty: "唐",
    category: "唐",
    summary: "秦时明月汉时关，万里长征人未还，但使龙城飞将在，不教胡马度阴山",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "出塞", original: `
秦时明月汉时关，
万里长征人未还，
但使龙城飞将在，
不教胡马度阴山
`, translation: `秦汉时候的明月和边关还在那里，如今戍守边关的将士却远赴万里不能回还。只要有像汉代飞将军李广那样的猛将镇守，就不会让北方的敌人跨过阴山一步。`, interpretation: `这首诗写于唐朝，当时边患频繁，战士们常年征战沙场、难以归家。诗人借古老的明月和边关，感叹战争的漫长——月亮和关口还是秦汉时的模样，可离家远征的将士却换了一代又一代。他特别提到汉代名将李广（人称'飞将军'），盼望着能有这样的英雄出现，守护边疆、保家卫国。这首七言绝句气象雄浑，被誉为唐代边塞诗的压卷之作，那句'不教胡马度阴山'更是千百年来保家卫国将士的共同心声。` }] },
  { id: 818, title: "凉州词",
    author: "王翰",
    dynasty: "唐",
    category: "唐",
    summary: "葡萄美酒夜光杯，欲饮琵琶马上催，醉卧沙场君莫笑，古来征战几人回",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "凉州词", original: `
葡萄美酒夜光杯，
欲饮琵琶马上催，
醉卧沙场君莫笑，
古来征战几人回
`, translation: `举起那装满葡萄酒的夜光杯，正想痛快地喝一杯，马背上弹起的琵琶声却催着将士们出发。就算喝醉了倒在战场上，你也别笑话我啊——自古以来，出征打仗的人，又有几个能活着回来呢？`, interpretation: `这首诗写于唐代盛极而衰的边塞岁月。那时边疆战事频繁，将士们远赴沙场，生死难料。诗中最妙的意象是“葡萄美酒”和“夜光杯”，一个香甜、一个闪亮，尽显军中宴席的豪奢；可紧接着琵琶催战，乐声变作出征的号角，欢乐瞬间被紧张取代。后两句最为动人——表面是醉话玩笑：“别笑我醉倒沙场啊”，骨子里却是对命运的坦然：既然打仗，谁不是把命别在裤腰带上？短短四句，把边塞将士的豪迈、悲壮与无奈全写尽了，历来被传诵为唐人边塞诗的压卷之作。` }] },
  { id: 819, title: "江畔独步寻花",
    author: "杜甫",
    dynasty: "唐",
    category: "唐",
    summary: "黄四娘家花满蹊，千朵万朵压枝低，留连戏蝶时时舞，自在娇莺恰恰啼",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "江畔独步寻花", original: `
黄四娘家花满蹊，
千朵万朵压枝低，
留连戏蝶时时舞，
自在娇莺恰恰啼
`, translation: `黄四娘家的花儿开得满满当当，把小路都挤满啦！成千上万朵花沉甸甸地压弯了枝条。蝴蝶在花丛中恋恋不舍地飞来飞去，一刻不停地翩翩起舞。自由自在的小黄莺叫声又娇又美，正好在这时候唱起歌来。`, interpretation: `这首诗写于杜甫在成都草堂安家的春天。当时他心情愉快，常常独自沿江边散步赏花。诗里没有一个大人物，却因为一朵朵鲜花、一只只蝴蝶、一声声莺啼，变得热闹又可爱。诗人用"压"字写出花朵的繁多沉甸，用"恰恰"形容黄莺啼声的清脆悦耳，画面感十足。后来"千朵万朵压枝低"成了描写春花盛放的名句，让我们闭上眼睛就能闻到花香呢！` }] },
  { id: 820, title: "赠花卿",
    author: "杜甫",
    dynasty: "唐",
    category: "唐",
    summary: "锦城丝管日纷纷，半入江风半入云，此曲只应天上有，人间能得几回闻",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "赠花卿", original: `
锦城丝管日纷纷，
半入江风半入云，
此曲只应天上有，
人间能得几回闻
`, translation: `锦官城里，天天都奏着悠扬的乐曲。
那动听的音乐，一半随着江风飘散，一半飞上了云端。
这样美妙的曲子，只应该在天上神仙处才有，
人世间又能听到几回呢？`, interpretation: `这首诗写于唐代安史之乱后，杜甫漂泊到成都。表面上是在赞美花敬定家的音乐动听得像仙乐，其实暗含劝诫——天上才有的曲子，人间不该随便享用，是在委婉地提醒他别太张扬。诗人用“锦城丝管”“江风入云”描绘出乐声悠扬、飘飘欲仙的画面，最后“天上有”“几回闻”的夸张说法，更让诗句传唱千古，成为赞美音乐的经典名句。` }] },
  { id: 821, title: "旅夜书怀",
    author: "杜甫",
    dynasty: "唐",
    category: "唐",
    summary: "星垂平野阔，月涌大江流，飘飘何所似，天地一沙鸥",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "旅夜书怀", original: `
细草微风岸危樯，
独夜舟星垂平野，
阔月涌大江流官，
应老病休飘飘何，
所似天地一沙鸥
`, translation: `微风轻轻吹拂着长满细草的河岸，竖着高高桅杆的小船在夜里孤独地停泊。星星低垂，天地辽阔，原野无边。一轮明月从奔腾的大江中升起，江水滚滚东流。我四处漂泊、年老多病，终于被罢了官。我这飘泊的一生像什么呢？就像天地之间一只孤零零的沙鸥。`, interpretation: `这首诗写于杜甫晚年，公元765年，他被迫离开成都，乘坐小船沿长江东下，一路上又老又病，官也丢了，心里非常难过。你看，他写的'细草''星垂''月涌'，把夜晚的江边写得又静又大，反衬出自己像只小沙鸥一样孤孤单单、随风飘荡。杜甫最厉害的就是用小小的景物写大大的心情，这首诗后来成了'身世漂泊'的经典名篇，'飘飘何所似，天地一沙鸥'更是千古名句，读来让人鼻子发酸呢！` }] },
  { id: 822, title: "江南逢李龟年",
    author: "杜甫",
    dynasty: "唐",
    category: "唐",
    summary: "正是江南好风景，落花时节又逢君，岐王宅里寻常见，崔九堂前几度闻",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "江南逢李龟年", original: `
岐王宅里寻常见，
崔九堂前几度闻，
正是江南好风景，
落花时节又逢君
`, translation: `以前啊，在岐王的府第里，我常常能见到你；在崔九的客厅前，我也好几次听你唱歌。想不到如今，在这风景正好的江南，又正好是落花纷纷的时节，竟然能再次遇见你。`, interpretation: `这首诗写于唐代宗大历五年（770年），当时安史之乱已结束多年，可战乱留下的伤痕到处都是。杜甫已是漂泊到江南的七旬老人，昔日繁华如梦，眼前却只剩落花飘零。李龟年呢，是当年红遍长安的大歌唱家，岐王和崔九都是权贵名流——诗的前两句用轻描淡写的方式，一下子把人带回那个歌舞升平的盛唐。可'落花'两字一出来，盛唐永远地凋谢了。短短二十八个字里装着半个世纪的沧桑，所以这句'落花时节又逢君'才能让千百年来的读者读到心里去：我们在最好的风景里相遇，可最美好的时代已经回不来了呀。` }] },
  { id: 823, title: "暮江吟",
    author: "白居易",
    dynasty: "唐",
    category: "唐",
    summary: "一道残阳铺水中，半江瑟瑟半江红，可怜九月初三夜，露似真珠月似弓",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "暮江吟", original: `
一道残阳铺水中，
半江瑟瑟半江红，
可怜九月初三夜，
露似真珠月似弓
`, translation: `夕阳的余晖静静地铺洒在江面上,江水一半是碧绿色,一半被染得通红。九月初三这个夜晚真是可爱呀!岸边的露水像圆润的珍珠一样晶莹剔透,天上的月亮像一把弯弯的小弓。`, interpretation: `这首诗写于白居易赴杭州赴任途中的九月傍晚。前两句抓住夕阳西下时江面光影变幻的一瞬,用“铺”字写出阳光的柔和,又以“半江瑟瑟半江红”画出冷暖交织的奇妙色彩。后两句镜头从江面转向天空与岸边,比喻新奇又亲切——露水像珍珠,月亮像弯弓,孩子也能立刻想象出画面。短短四句,色彩、声音、形状俱全,既有夕阳的壮丽,又有夜晚的清丽,展现了白居易诗歌“明白如话却韵味悠长”的艺术特色,也难怪“半江瑟瑟半江红”成为千古传诵的名句。` }] },
  { id: 824, title: "赋得古原草送别",
    author: "白居易",
    dynasty: "唐",
    category: "唐",
    summary: "离离原上草，一岁一枯荣，野火烧不尽，春风吹又生，远芳侵古道，晴翠接荒城，又送王孙去，萋萋满别情",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "赋得古原草送别", original: `
离离原上草，
一岁一枯荣，
野火烧不尽，
春风吹又生，
远芳侵古道，
晴翠接荒城，
又送王孙去，
萋萋满别情
`, translation: `原野上的草长得多么茂盛啊！每年秋天枯萎，春天又变得绿油油的。野火再猛也烧不光它，等春风一吹，它又冒出芽来啦。远处的草蔓延到古老的道路上，阳光下那一片翠绿连着荒凉的古城。我又要送别朋友远去啦，那满地的青草，正像我们心里满满的舍不得呀。`, interpretation: `这是白居易十六岁时写的诗，当时他从江南到长安去考科举，看到长安城外一片古老的原野，长满了野草，心里很有感触。诗里最厉害的就是把"野草"和"送别"连在了一起——草虽然年年被烧、被踩，却永远烧不死、踩不光，多么坚强！这种顽强的生命力，正好用来鼓励要远行的朋友：不管遇到什么困难，都要像小草一样，勇敢地重新生长。"野火烧不尽，春风吹又生"成了千古名句，后来很多人用它来形容不怕挫折、充满希望的精神。这首诗语言特别朴素，像说话一样，所以小朋友们读起来也不会觉得难懂。` }] },
  { id: 825, title: "钱塘湖春行",
    author: "白居易",
    dynasty: "唐",
    category: "唐",
    summary: "孤山寺北贾亭西，水面初平云脚低，几处早莺争暖树，谁家新燕啄春泥，乱花渐欲迷人眼，浅草才能没马蹄，最爱湖东行不足，绿杨阴里白沙堤",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "钱塘湖春行", original: `
孤山寺北贾亭西，
水面初平云脚低，
几处早莺争暖树，
谁家新燕啄春泥，
乱花渐欲迷人眼，
浅草才能没马蹄，
最爱湖东行不足，
绿杨阴里白沙堤
`, translation: `从孤山寺的北面一直走到贾亭的西边，湖水刚好涨得和堤岸一样平，远处的白云低低地垂下来，好像要碰到湖面似的。早春时节，几只小黄莺争着飞向向阳的树枝去晒太阳，是谁家的新来燕子正忙着衔泥筑巢呢？路边五颜六色的野花越开越密，快要让人看花眼了，脚下短短的春草刚好能盖住马蹄印。我最喜欢湖东这一带了，总觉得怎么走都走不够，那杨柳成排、绿荫遮蔽的地方，就是有名的白沙堤啊。`, interpretation: `这首诗写于唐穆宗长庆三年（823年），当时白居易刚到杭州做刺史不久，趁着春天骑马踏青，满心欢喜地记下了这一路的好风景。他最厉害的地方是"用眼睛听声音"——黄莺叫、燕子飞、花儿开、草儿长，都变成了诗。诗里藏着许多春天的"小信号"：莺是"早莺"、燕是"新燕"、草是"浅草"，一个"早"字、一个"新"字、一个"浅"字，就告诉你这是刚刚到来的春天。这首诗后来成了写西湖春天的"代表作"，连"白沙堤"都因为它被叫作"白堤"，直到现在你去西湖，还能找到这条一千两百年前的古堤呢！` }] },
  { id: 826, title: "望天门山",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "天门中断楚江开，碧水东流至此回，两岸青山相对出，孤帆一片日边来",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "望天门山", original: `
天门中断楚江开，
碧水东流至此回，
两岸青山相对出，
孤帆一片日边来
`, translation: `长江水浩浩荡荡冲开了天门山，碧绿的江水向东流到这里突然转了个弯。两岸高高的青山相互对峙着从两边冒出来，一片孤零零的小船从太阳升起的地方悠悠驶来。`, interpretation: `这首诗是李白25岁仗剑出蜀，乘坐小船沿长江东下游历时金陵时写下的。那时的他年轻气盛，满怀抱负，眼前的长江天险在他看来不是阻碍，而是一幅壮丽的画卷。诗中有两个特别有意思的意象：一个是'断'字，仿佛大山被神斧劈开；一个是'孤帆'，在巨大山水之间显得那么小，却又那么自由。整首诗最大的特色是'动'与'静'的对比——山是静的，水是流的，船是动的，日是升的，读起来画面感十足。后来'孤帆远影碧空尽'成了中国人送别时最经典的画面，而天门山也因这首诗名扬天下，至今仍是长江边著名的景点。` }] },
  { id: 827, title: "赠汪伦",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "李白乘舟将欲行，忽闻岸上踏歌声，桃花潭水深千尺，不及汪伦送我情",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "赠汪伦", original: `
李白乘舟将欲行，
忽闻岸上踏歌声，
桃花潭水深千尺，
不及汪伦送我情
`, translation: `李白我坐上小船，正准备出发走呢。忽然听到岸上传来一阵脚步声和唱歌的声音。桃花潭的水呀，就算有上千尺那么深，也比不上汪伦送别我的这份情谊深厚啊！`, interpretation: `这首诗写于唐代天宝年间，李白在安徽桃花潭游玩时，好朋友汪伦热情款待了他。离别时，汪伦没到船边送行，而是在岸上边走边唱踏歌为他送别，李白十分感动，便写下了这首小诗送给汪伦。短短四句，没有华丽辞藻，却用“桃花潭水深千尺”这样夸张的比喻，反衬出朋友间真挚深厚的情谊。语言明白如话，朗朗上口，是小学生学古诗最经典的友情诗之一。` }] },
  { id: 828, title: "黄鹤楼送孟浩然之广陵",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "故人西辞黄鹤楼，烟花三月下扬州，孤帆远影碧空尽，唯见长江天际流",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "黄鹤楼送孟浩然之广陵", original: `
故人西辞黄鹤楼，
烟花三月下扬州，
孤帆远影碧空尽，
唯见长江天际流
`, translation: `老朋友向西告别了黄鹤楼,
在繁花似锦的三月顺流而下到扬州。
那一片孤舟的远影渐渐消失在碧蓝的天空尽头,
只看见浩浩荡荡的长江水,奔流到天边。`, interpretation: `这是李白在武汉黄鹤楼送别好友孟浩然时写下的名篇。公元730年三月,正是江南最美的时节,柳絮飞舞、百花盛开,李白心中却满是不舍。诗中最妙的画面是最后两句:朋友的小船越走越远,最后连影子都看不见了,可李白还站在江边,望着滚滚长江水一直流向天边,把那份思念和牵挂都藏进了江水之中。短短四句,没有一个“惜别”字,却比说一千遍再见更让人感动。后来“烟花三月”成了描写春天的经典词语,也让黄鹤楼和扬州因为这首诗而名扬天下。` }] },
  { id: 829, title: "早发白帝城",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "朝辞白帝彩云间，千里江陵一日还，两岸猿声啼不住，轻舟已过万重山",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "早发白帝城", original: `
朝辞白帝彩云间，
千里江陵一日还，
两岸猿声啼不住，
轻舟已过万重山
`, translation: `早上我告别了高高的白帝城，那里彩云缭绕好像在仙境一样。坐上船顺流而下，一千里的江陵只用一天就能到。两岸山上的猿猴一直叫个不停，声音在山谷里回荡。小船轻快得像飞一样，不知不觉已经穿过了无数座高山。`, interpretation: `这首诗写于李白被流放途中遇赦的时候，公元759年，他高兴得像飞起来一样，从白帝城坐船回老家江陵。诗里有三个特别有意思的画面：彩云缭绕的白帝城、一直叫的猿猴、飞快的小船。最大的特色就是一个字——快！整首诗都透着轻快兴奋的心情，连猿猴的叫声都变成了欢快的伴奏。最后一句'轻舟已过万重山'特别有名，成了千古名句，形容速度特别快、心情特别爽的样子。` }] },
  { id: 830, title: "望月怀远（节选）",
    author: "张九龄",
    dynasty: "唐",
    category: "唐",
    summary: "海上生明月，天涯共此时，情人怨遥夜，竟夕起相思，灭烛怜光满，披衣觉露滋，不堪盈手赠，还寝梦佳期",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "望月怀远（节选）", original: `
海上生明月，
天涯共此时，
情人怨遥夜，
竟夕起相思，
灭烛怜光满，
披衣觉露滋，
不堪盈手赠，
还寝梦佳期
`, translation: `大海上升起了一轮明亮的月亮，远在天边的我和亲人朋友却望着同一个月亮。思念的人啊总抱怨夜晚太漫长了，整夜都因为想念而睡不着觉。吹灭蜡烛，我爱惜这满屋的月光；披上衣服走出去，才发觉露水已经沾湿了衣服。我捧不起这满手的月光送给你，还是回去睡觉吧，也许在梦里能和你相见。`, interpretation: `这是唐代名相张九龄被贬荆州时写下的诗。古代交通不便，相隔两地的人只能共看同一轮明月来寄托思念，所以月亮在中国诗词里常常代表相思。诗中'海上生明月'一句最为经典，气魄宏大，意境优美，成为千古传诵的名句。后来苏轼的名句'但愿人长久，千里共婵娟'，就是从这首诗的意境中得到启发而写成的。` }] },
  { id: 831, title: "望洞庭",
    author: "刘禹锡",
    dynasty: "唐",
    category: "唐",
    summary: "湖光秋月两相和，潭面无风镜未磨，遥望洞庭山水翠，白银盘里一青螺",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "望洞庭", original: `
湖光秋月两相和，
潭面无风镜未磨，
遥望洞庭山水翠，
白银盘里一青螺
`, translation: `秋天夜晚，洞庭湖的水光和皎洁的月光相互映衬，柔和又宁静。湖面没有风，平静得像一面还没打磨过的铜镜。远远望去，洞庭湖的山水苍翠碧绿。在那洁白银盘似的湖面上，君山就像一颗小巧可爱的青色田螺。`, interpretation: `这首诗写于刘禹锡被贬官到湖南的秋天夜晚。当时他心情郁闷，却依然被眼前的美景打动。他把月亮下的洞庭湖比作一面没磨亮的镜子，又把整个湖面比作白银盘子，把湖中的君山比作盘子里的青田螺——这个想象实在太妙了！一个小小的比喻，就画出了一幅又大又美的山水画。这首诗也因为最后两句太有名了，成了描写洞庭湖的经典之作。` }] },
  { id: 832, title: "竹枝词",
    author: "刘禹锡",
    dynasty: "唐",
    category: "唐",
    summary: "杨柳青青江水平，闻郎江上踏歌声，东边日出西边雨，道是无晴却有晴",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "竹枝词", original: `
杨柳青青江水平，
闻郎江上踏歌声，
东边日出西边雨，
道是无晴却有晴
`, translation: `杨柳绿油油的，江水平平静静地流着。姑娘听到江面上小伙子边走边唱着歌。东边太阳出来了，西边却还在下雨。说是没有晴天吧，其实还是有晴天的。`, interpretation: `这首诗大约写于刘禹锡被贬到夔州（今重庆奉节）的时候，那时候他常听到当地人唱一种叫《竹枝词》的山歌，觉得特别有意思，就学着写了九首，这首是其中最有名的一首。诗里最妙的是后两句，用忽晴忽雨的天气，比喻小姑娘对心上人又疑惑又期待的心情——猜不透他到底喜不喜欢自己，所以用天气来打比方，特别生动！这种用眼前景说心里话的方法，后来很多诗人都爱用，是唐诗里特别经典的名句呢。` }] },
  { id: 833, title: "乌衣巷",
    author: "刘禹锡",
    dynasty: "唐",
    category: "唐",
    summary: "朱雀桥边野草花，乌衣巷口夕阳斜，旧时王谢堂前燕，飞入寻常百姓家",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "乌衣巷", original: `
朱雀桥边野草花，
乌衣巷口夕阳斜，
旧时王谢堂前燕，
飞入寻常百姓家
`, translation: `朱雀桥边长满了野草和野花，乌衣巷口只有快要落山的夕阳斜照着。从前在王导和谢安家大堂前筑巢的燕子，现在却飞进了普通老百姓的房子里住下。`, interpretation: `这首诗写于唐朝，诗人刘禹锡路过南京的乌衣巷，想起这里曾经是东晋最显赫的王导、谢安两大家族的宅邸，热闹非凡。可如今再看，豪门府第早已不见踪影，只剩野草夕阳，一片冷清。就连当年在王谢大宅屋檐下筑巢的燕子，如今也飞到普通人家去了。一千年前的繁华就这么悄悄变了模样。诗人用'燕子'这个小小的意象，把世事无常讲得特别有画面感——燕子认得旧巢，可旧巢早就不在了。后人常说'旧时王谢堂前燕，飞入寻常百姓家'，就是用这个典故来感慨兴亡盛衰。` }] },
  { id: 834, title: "秋词",
    author: "刘禹锡",
    dynasty: "唐",
    category: "唐",
    summary: "自古逢秋悲寂寥，我言秋日胜春朝，晴空一鹤排云上，便引诗情到碧霄",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "秋词", original: `
自古逢秋悲寂寥，
我言秋日胜春朝，
晴空一鹤排云上，
便引诗情到碧霄
`, translation: `从古以来人们一遇到秋天就觉得悲伤寂寞，可是我觉得秋天比春天还要好。你看，一只白鹤推开云朵，展翅飞上晴朗的天空，那雄壮的样子一下子就激发了我的诗意，让我忍不住想一直写到那高高的蓝天上去。`, interpretation: `这首诗写于刘禹锡被贬官的时候，但他并没有像别人那样因为秋天而感伤。古人常说"悲秋"，他却偏说秋天比春天还美，这种看法在当时非常特别，所以叫"我言"，就是要和古人唱反调呢！诗中最美的画面是一只白鹤在蓝天上飞翔，云彩都被它推开，这个"排"字特别有力量，让人觉得秋天天高气爽、充满活力。这首诗告诉我们：换个角度看世界，心情就会不一样。后来很多人喜欢用它来形容积极乐观的人生态度。` }] },
  { id: 835, title: "清明",
    author: "杜牧",
    dynasty: "唐",
    category: "唐",
    summary: "清明时节雨纷纷，路上行人欲断魂，借问酒家何处有，牧童遥指杏花村",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "清明", original: `
清明时节雨纷纷，
路上行人欲断魂，
借问酒家何处有，
牧童遥指杏花村
`, translation: `清明节这天，雨淅淅沥沥地下个不停。赶路的人心里闷闷的，好像丢了魂一样难受。我向别人打听：附近哪里有小酒馆能歇歇脚、喝杯酒呢？路边的小牧童伸手指向远处，告诉我：杏花开得正旺的那个村子就有呀！`, interpretation: `这首小诗写于晚唐，那时候社会有点乱，人们出门常带着忧愁。清明本来是扫墓祭祖的日子，又赶上细雨，更让人心里不好受。诗里有三个特别有意思的画面：纷纷的雨、想找酒喝的路人、指路的牧童，还有远远的杏花村。杜牧最厉害的地方就是用短短四句，把“雨”“人”“酒”“花”全串在了一起，画一样美，还让你忍不住想问一句：那杏花村的酒，到底是什么味道？后来“杏花村”三个字就变成了人人都知道的好地方，连酒家都爱拿它当招牌呢！` }] },
  { id: 836, title: "山行",
    author: "杜牧",
    dynasty: "唐",
    category: "唐",
    summary: "远上寒山石径斜，白云生处有人家，停车坐爱枫林晚，霜叶红于二月花",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "山行", original: `
远上寒山石径斜，
白云生处有人家，
停车坐爱枫林晚，
霜叶红于二月花
`, translation: `沿着弯弯曲曲的石子小路，慢慢地爬上了又高又冷的山。在白云飘出来的地方，竟然还住着几户人家。我停下车来不走，是因为太喜欢这傍晚的枫树林了。呀，你看！被霜打过的枫叶比二月里盛开的鲜花还要红呢！`, interpretation: `这是杜牧晚年写的一首秋日山行小诗，充满了对自然的热爱。诗里最妙的是'白云生处有人家'，白云缭绕的山间竟然有村庄，多么幽静又有烟火气呀！整首诗最大的特色是'以乐景写秋意'——别人都觉得秋天萧瑟，杜牧却觉得霜打过的红枫比春天的花还美。这种对秋天的喜爱，让整首诗明快又温暖，一点儿也不伤感。后来'霜叶红于二月花'成了千古名句，画家们最爱画这种火红的山林呢！` }] },
  { id: 837, title: "过华清宫",
    author: "杜牧",
    dynasty: "唐",
    category: "唐",
    summary: "长安回望绣成堆，山顶千门次第开，一骑红尘妃子笑，无人知是荔枝来",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "过华清宫", original: `
长安回望绣成堆，
山顶千门次第开，
一骑红尘妃子笑，
无人知是荔枝来
`, translation: `从长安回头望去，骊山华清宫的楼阁像一堆锦绣一样壮丽。山顶上无数宫门一道接一道地打开。一匹快马扬起红色的尘土飞奔而来，妃子看见了开心地笑了。没有人知道这是从南方紧急送来的新鲜荔枝呀。`, interpretation: `这首诗写的是唐玄宗为了博杨贵妃开心，下令从南方千里迢迢运送新鲜荔枝进京的故事。杜牧生活在晚唐，他借古讽今，提醒统治者不要因为贪图享乐而荒废朝政。诗中最妙的就是"一骑红尘妃子笑"这句——只写妃子开心的笑容，却不提跑死了多少匹马、累坏了多少人，这就是"以小见大"的写法。短短四句，既有画面感，又藏着深深的感慨，成了千古传诵的名句。` }] },
  { id: 838, title: "书湖阴先生壁",
    author: "王安石",
    dynasty: "宋",
    category: "宋",
    summary: "茅檐长扫净无苔，花木成畦手自栽，一水护田将绿绕，两山排闼送青来",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "书湖阴先生壁", original: `
茅檐长扫净无苔，
花木成畦手自栽，
一水护田将绿绕，
两山排闼送青来
`, translation: `茅草屋顶的院子里，经常打扫得干干净净，连青苔都没有。 花草树木整整齐齐种成一行行，都是主人亲手栽种的。 一条小河弯弯地绕着绿色的田地流过，像是在保护着庄稼。 两座大山从门外推开门，把青翠的山色送到了眼前。`, interpretation: `这是王安石退居金陵时，题在邻居杨德逢家墙上的诗。湖阴先生是杨德逢的号，王安石和他是好友，常来常往。诗中没有直接写人，却用干净的小院、亲手栽的花木，悄悄告诉我们：住在这里的人一定勤劳又爱生活。后两句最妙——小河像卫士一样守护田地，青山像好朋友一样推门送绿，普通的山水一下子有了人情味，读起来又对仗又活泼。这种'把山水写活'的写法，让这首小诗成了宋诗里写田园的经典名句。` }] },
  { id: 839, title: "登飞来峰",
    author: "王安石",
    dynasty: "宋",
    category: "宋",
    summary: "飞来山上千寻塔，闻说鸡鸣见日升，不畏浮云遮望眼，自缘身在最高层",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "登飞来峰", original: `
飞来山上千寻塔，
闻说鸡鸣见日升，
不畏浮云遮望眼，
自缘身在最高层
`, translation: `登上飞来峰山顶那座极高的塔，听说站在上面，鸡叫的时候就能看到太阳升起。不用担心漂浮的云彩挡住我的视线，因为我本来就站在最高的地方。`, interpretation: `这首诗写于王安石三十岁那年，他准备去浙江鄞县做官，路过杭州飞来峰时一口气写下的。那时候他年轻气盛，满脑子都是改革的想法。这座山上的塔特别高，诗人站在最高处，感觉天上的云都在脚下，心里特别开阔。整首诗最妙的地方就是后两句，'浮云'其实是在说那些挡路的小人和困难，'最高层'是说只要自己有本事、站得高，什么都不用怕。这两句成了千古名句，后来很多人遇到困难时都会想到它，给自己打气！` }] },
  { id: 840, title: "夏日绝句",
    author: "李清照",
    dynasty: "宋",
    category: "宋",
    summary: "生当作人杰，死亦为鬼雄，至今思项羽，不肯过江东",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "夏日绝句", original: `
生当作人杰，
死亦为鬼雄，
至今思项羽，
不肯过江东
`, translation: `活着的时候，应当做人中的豪杰；死了以后，也要成为鬼中的英雄。直到今天，人们还在思念项羽，只因为他宁可自杀也不愿逃回江东。`, interpretation: `这首诗写于北宋灭亡、南宋偏安江南的背景下。李清照面对国土沦丧、当权者只顾逃命的现实，心中满是悲愤。她借两千年前项羽乌江自刎的壮举，讽刺那些苟且偷安的南宋权贵。诗中最打动人的是'不肯过江东'五个字——项羽本可渡江逃生、卷土重来，却选择以死明志，这份骨气正是李清照心中英雄的模样。全诗语言刚健有力，短短二十字，字字铿锵，既是对英雄的追思，更是对懦夫的鞭挞。后人常以'生当作人杰，死亦为鬼雄'自勉，成为流传千古的名句。` }] },
  { id: 841, title: "如梦令·常记溪亭日暮",
    author: "李清照",
    dynasty: "宋",
    category: "宋",
    summary: "常记溪亭日暮，沉醉不知归路，兴尽晚回舟，误入藕花深处，争渡，争渡，惊起一滩鸥鹭",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "如梦令·常记溪亭日暮", original: `
常记溪亭日暮。
沈醉不知归路。
兴尽晚回舟，
误入藕花深处。
争渡。
争渡。
惊起一滩鸥鹭。
`, translation: `常常想起那天在溪边亭子里玩到太阳落山的时候。喝得醉醺醺的，竟然找不到回家的路了。游兴尽了，天黑了才划船往回走，没想到却划进了荷花丛里。快划呀，快划呀！小船一阵乱冲乱撞，把沙滩上休息的水鸟鸥鸟和白鹭都惊吓得飞了起来。`, interpretation: `这是李清照少女时代的小词，写得特别活泼可爱！那时候她还是个十几岁的姑娘，跟朋友们出去野游，玩得太开心，喝了点小酒，划船回家时迷了路，一不小心闯进了荷花荡子里，把水鸟都吓飞了。词里用“争渡，争渡”的重复，写出了小船手忙脚乱的热闹劲儿，读着都让人跟着着急又忍不住笑。一千年前这位才女小姑娘的调皮劲儿，跟咱们今天的孩子一模一样，是不是特别亲切？这首小令虽然短，却把少女的快乐和惊慌写得活灵活现，后来成了千古名篇。` }] },
  { id: 842, title: "如梦令·昨夜雨疏风骤",
    author: "李清照",
    dynasty: "宋",
    category: "宋",
    summary: "昨夜雨疏风骤，浓睡不消残酒，试问卷帘人，却道海棠依旧，知否，知否，应是绿肥红瘦",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "如梦令·昨夜雨疏风骤", original: `
昨夜雨疏风骤，
浓睡不消残酒。
试问卷帘人，
却道海棠依旧。
知否，
知否？
应是绿肥红瘦
`, translation: `昨天夜里，雨点稀疏但风刮得又急又猛。我睡得很沉，醒来后昨晚喝的酒意还没完全消散。试着问正在卷帘子的侍女，外面的花怎么样，她却随口回答说海棠花还是老样子。知道吗？知道吗？应该是绿叶变得更加茂盛，红花却变得稀少零落了。`, interpretation: `这是李清照少女时期的作品，写她清晨醒来关心院中海棠的小事。别看只是问花，却藏着细腻的心思：雨打风吹后，她担心花会凋谢，可粗心的侍女根本不懂她的牵挂。词中最妙的就是结尾的'绿肥红瘦'四个字——绿叶茂盛、花儿稀少，五个字就把雨后海棠的模样写得活灵活现，成了千古名句。后来很多人写春愁、写惜花，都绕不开这四个字。李清照真不愧是宋代最厉害的女词人，连担心一朵花都能写得这么美！` }] },
  { id: 843, title: "十一月四日风雨大作",
    author: "陆游",
    dynasty: "宋",
    category: "宋",
    summary: "僵卧孤村不自哀，尚思为国戍轮台，夜阑卧听风吹雨，铁马冰河入梦来",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "十一月四日风雨大作", original: `
僵卧孤村不自哀，
尚思为国戍轮台，
夜阑卧听风吹雨，
铁马冰河入梦来
`, translation: `我直挺挺地躺在孤零零的村子里，并不为自己感到悲伤。我还在想着，要替国家去边疆守卫呢。深夜里，我躺在床上听着外面的风雨声。不知不觉，在梦里，我骑着披着铁甲的战马，跨过冰封的河面，冲向了战场。`, interpretation: `这是南宋爱国诗人陆游晚年写下的名篇，当时他被罢官回乡，住在山阴一个偏僻的小村子里。虽然身体衰老、生活困苦，但这位六十八岁的老人心里想的，依然是去北方收复被金人占领的国土。诗人没有直接写“我很爱国”，而是用梦境来表达心愿——风雨声中，他梦见自己骑着战马、踏过冰河，奔赴战场。读起来既豪迈又让人心酸。后来“铁马冰河入梦来”成了千古名句，让无数读它的人感受到：即使在最艰难的时候，只要心中有信念，人就不会被打倒。` }] },
  { id: 844, title: "示儿",
    author: "陆游",
    dynasty: "宋",
    category: "宋",
    summary: "死去元知万事空，但悲不见九州同，王师北定中原日，家祭无忘告乃翁",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "示儿", original: `
死去元知万事空，
但悲不见九州同，
王师北定中原日，
家祭无忘告乃翁
`, translation: `我本来就知道，人死了以后，世间的一切事情都和自己没有关系了。唯一让我感到悲伤的，是没能亲眼看到国家统一。当朝廷的军队收复北方中原的那一天，你们在家里祭祀祖先的时候，可千万不要忘记把这个好消息告诉你们的爸爸呀！`, interpretation: `这是八十五岁的陆游临终前写给儿子们的最后一首诗。背景是南宋偏安一隅、北伐无望的年代，陆游一生抗金报国，却壮志未酬。诗中最动人的是第二句的'悲'和第四句的'告'——一个老人最大的遗憾不是生死，而是山河破碎；临终最大的心愿，是儿孙能亲耳听到统一的消息。这种把个人命运和家国紧紧绑在一起的情怀，让这首诗成为千古名篇。它没有华丽的辞藻，字字都是肺腑之言，读来让人鼻子发酸，也让我们懂得了什么是真正的爱国。` }] },
  { id: 845, title: "秋夜将晓出篱门迎凉有感",
    author: "陆游",
    dynasty: "宋",
    category: "宋",
    summary: "三万里河东入海，五千仞岳上摩天，遗民泪尽胡尘里，南望王师又一年",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "秋夜将晓出篱门迎凉有感", original: `
三万里河东入海，
五千仞岳上摩天，
遗民泪尽胡尘里，
南望王师又一年
`, translation: `三万里长的黄河啊，一路向东奔流入大海；五千仞高的华山啊，山峰直耸快要碰到天。可叹沦陷区的百姓，眼泪都快流干了，在金兵铁蹄下苦苦煎熬。他们年年往南眺望，盼着大宋的军队来收复失地，又整整过了一年。`, interpretation: `这首诗写在南宋时期，当时北方大片土地被金国占领，陆游已经六十八岁，住在山阴老家。他晚上热得睡不着，出门吹吹凉风，心里却一点都不凉——因为他日夜惦记着被金人欺压的北方百姓。诗里“三万里河”“五千仞岳”可不是随便说说的数字，黄河和华山是咱们中华民族的象征，陆游用夸张的数字告诉小朋友们：这么大的国家，怎么能被人占去一半呢？“遗民泪尽”四个字最让人心疼，眼泪都哭干了还在等啊等。最妙的是“南望王师又一年”，一个“又”字，藏着多少失望和坚持。后来这句诗成了爱国诗词里的名句，连小学生都知道：盼啊盼，又是一年！` }] },
  { id: 846, title: "题临安邸",
    author: "林升",
    dynasty: "宋",
    category: "宋",
    summary: "山外青山楼外楼，西湖歌舞几时休，暖风熏得游人醉，直把杭州作汴州",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "题临安邸", original: `
山外青山楼外楼，
西湖歌舞几时休，
暖风熏得游人醉，
直把杭州作汴州
`, translation: `青山连着青山，高楼挨着高楼，一眼望不到头啊！西湖边上的歌舞声啊，什么时候才能停下来？暖洋洋的风把游人们都吹得醉醺醺的，他们简直把这杭州当成了当年的汴州！`, interpretation: `这首诗写在南宋时期，那时候金兵占了北方，皇帝逃到杭州，可朝廷里的大官们只知道在西湖边唱歌跳舞、吃喝玩乐，根本不想着打回老家去！诗人林升看了很生气，就在一家旅馆的墙上写下了这首诗。'山外青山楼外楼'写出了杭州的繁华热闹，可越繁华就越让人心酸——他们把临时的避难所当成了永远的安乐窝，忘了国仇家恨！最后一句'直把杭州作汴州'成了千古名句，就是说当官的把杭州当成了老家汴州一样享受，早忘了要收复失地。这首诗像一把小刀，轻轻地就刺中了那些只顾享乐的人，所以一直流传到今天，提醒我们不能贪图安逸、忘记该做的事。` }] },
  { id: 847, title: "游园不值",
    author: "叶绍翁",
    dynasty: "宋",
    category: "宋",
    summary: "应怜屐齿印苍苔，小扣柴扉久不开，春色满园关不住，一枝红杏出墙来",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "游园不值", original: `
应怜屐齿印苍苔，
小扣柴扉久不开，
春色满园关不住，
一枝红杏出墙来
`, translation: `大概是主人爱惜青苔，怕我的木屐踩出脚印吧。我轻轻地敲那柴门，可敲了好久也没人来开。可是这满园的春色哪能关得住？瞧，一枝红色的杏花已经探出墙头，悄悄开啦！`, interpretation: `这首诗写在南宋，当时诗人想拜访朋友，敲门没人应，心里有点失落。但他没有抱怨，反而被墙头探出的一枝红杏逗乐了！诗人用"小扣"代替"猛敲"，特别有礼貌，特别有耐心。一个"出"字用得最妙，杏花像是调皮的小孩，憋不住要跑出来看世界。这首诗让"红杏出墙"成了千古名句，后来人们还喜欢用它来形容新事物挡也挡不住呢！` }] },
  { id: 848, title: "观书有感",
    author: "朱熹",
    dynasty: "宋",
    category: "宋",
    summary: "半亩方塘一鉴开，天光云影共徘徊，问渠那得清如许，为有源头活水来",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "观书有感", original: `
半亩方塘一鉴开，
天光云影共徘徊，
问渠那得清如许，
为有源头活水来
`, translation: `半亩大的方形池塘像一面镜子打开了一样，
蓝天和云影在水面上一起晃来晃去。
要问这池水为什么这样清澈呢？
因为有源源不断的活水从源头流过来呀。`, interpretation: `这首诗是南宋大儒朱熹的读书心得，写于他读书有感的时候。诗里最妙的地方是把一本本书比作清澈的池塘，把源源不断的学习比作活水！诗人看着水塘，忽然想到：书读得透彻明白，正是因为不断有新的知识流进脑海呀。这首小诗最厉害的是“借景说理”，不说大道理，只给你看一幅清清亮亮的水中天云图，让你自己去想。后来“为有源头活水来”成了千古名句，意思是人要活到老学到老，才不会头脑发僵。今天我们读书，也要做那个“源头活水”哦！` }] },
  { id: 849, title: "春日",
    author: "朱熹",
    dynasty: "宋",
    category: "宋",
    summary: "胜日寻芳泗水滨，无边光景一时新，等闲识得东风面，万紫千红总是春",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "春日", original: `
胜日寻芳泗水滨，
无边光景一时新，
等闲识得东风面，
万紫千红总是春
`, translation: `天气晴朗的好日子，我去泗水河边寻找花草的芬芳。那里无边无际的风光景色，让人眼前一亮，全都是新的。轻轻松松就看到了春风温柔的面容，到处是万紫千红——到处都是春天呀！`, interpretation: `这首诗写于南宋，那时候朱熹是位大学问家，他特别推崇孔子。泗水是孔子讲学的地方，朱熹虽然没去过，但他心里一直向往那里，所以写诗时就说自己"寻芳泗水滨"。诗里说的"东风"和"万紫千红"，表面上写春天百花盛开的美景，其实是在说：只要你用心去感受，就能发现圣人的道理就像春风一样无处不在。整首诗语言明快，像小朋友写春游日记一样活泼，所以"万紫千红总是春"成了千古名句，咱们现在形容春天，还会常常用上它呢！` }] },
  { id: 850, title: "雪梅",
    author: "卢梅坡",
    dynasty: "宋",
    category: "宋",
    summary: "梅雪争春未肯降，骚人阁笔费评章，梅须逊雪三分白，雪却输梅一段香",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "雪梅", original: `
梅雪争春未肯降，
骚人阁笔费评章，
梅须逊雪三分白，
雪却输梅一段香
`, translation: `梅花和雪花都争着报春，谁也不肯服输。写诗的诗人放下笔，琢磨了半天也分不清谁更好。梅花比雪少了三分洁白，雪花却比梅花少了一段清香。`, interpretation: `这首诗写于南宋，那时候诗人特别喜欢用梅花和雪花来比高低。卢梅坡特别聪明，他没有说谁最好，而是说梅花和雪花各有各的长处——雪更白，梅更香。这样写告诉大家：每个人都有自己的优点，要学会欣赏别人。这首诗最有名的是后两句，短短二十个字就把梅和雪的特点写活了，成了小朋友写作文时最爱引用的名句呢！` }] },
  { id: 851, title: "竹石",
    author: "郑燮",
    dynasty: "清",
    category: "清",
    summary: "咬定青山不放松，立根原在破岩中，千磨万击还坚劲，任尔东西南北风",
    tags: "清,经典",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "竹石", original: `
咬定青山不放松，
立根原在破岩中，
千磨万击还坚劲，
任尔东西南北风
`, translation: `竹子紧紧咬住青山，一点也不肯放松。它的根牢牢地扎在岩石缝里。经历千万次磨难打击，它依然坚强挺立。任凭你东西南北的狂风怎么吹，我都不怕！`, interpretation: `这首诗是清代画家郑板桥写的，他最爱画竹。诗写的是生长在山崖石缝里的竹子。竹子扎根在破石头中，被风吹、被雨打、被霜冻，可它就是不肯倒下。这里把竹子当成有骨气的人来写，其实郑板桥是在说自己——做人要有骨气，不能向困难低头。这首诗里最有名的是'千磨万击还坚劲，任尔东西南北风'，现在人们常用它来鼓励遇到困难的朋友，要像竹子一样坚强。` }] },
  { id: 852, title: "己亥杂诗·其五",
    author: "龚自珍",
    dynasty: "清",
    category: "清",
    summary: "浩荡离愁白日斜，吟鞭东指即天涯，落红不是无情物，化作春泥更护花",
    tags: "清,经典",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "己亥杂诗·其五", original: `
浩荡离愁白日斜，
吟鞭东指即天涯，
落红不是无情物，
化作春泥更护花
`, translation: `我满怀着浩荡无边的离愁，正赶上夕阳西下。我挥起马鞭指向东方，踏上漫长的路途，离开京城就像到了天涯。飘落的红花并不是无情的东西，它们化作春天的泥土，会继续滋养、保护新生的花朵。`, interpretation: `这首诗写于1839年，龚自珍辞官离开北京回家乡。当时清朝腐败，列强逼近，他心里装着对国家命运的担忧。诗里最打动人的是后两句：落花会变成泥土，泥土又去呵护新花——就像一个离开岗位的老人，虽然走了，但仍然想为国家和年轻人出一份力。这种“活到老、奉献到老”的精神，让这首诗成了千古名句，常常被老师用来鼓励学生。` }] },
  { id: 853, title: "刺巴郡守诗",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "狗吠何喧喧，有吏来在门，披衣出门应，府记欲得钱，语穷乞请期，吏怒反见尤",
    tags: "汉,讽刺",
    color: "#dc2626",
    sections:[    { id: 1, title: "刺巴郡守诗", original: `
狗吠何喧喧，
有吏来在门，
披衣出门应，
府记欲得钱，
语穷乞请期，
吏怒反见尤
`, translation: `狗叫声怎么这么吵闹，原来是有官吏来到了门前。赶紧披上衣服出门去应对，官府的文书说就是要来收钱。我苦苦哀求想要宽限几天，官吏却发怒反而责怪起我来。`, interpretation: `这首诗出自东汉末年，当时地方官吏横征暴敛，老百姓苦不堪言。诗中没有华丽的词藻，只是用最朴实的语言，描绘了一个普通百姓被官府上门催钱的场景——“披衣出门”说明事出突然，“乞请期”是低声下气地哀求，“吏怒反见尤”最让人心寒：求情不成反被责怪。短短六句，活画出一个凶恶小吏和无奈百姓的形象，是汉代乐府诗中难得的讽刺佳作。它让我们看到，老百姓对公平正义的呼喊，从古至今都在回荡。` }] },
  { id: 854, title: "古艳歌",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "茕茕白兔，东走西顾，衣不如新，人不如故",
    tags: "汉,经典",
    color: "#dc2626",
    sections:[    { id: 1, title: "古艳歌", original: `
茕茕白兔，
东走西顾，
衣不如新，
人不如故
`, translation: `孤孤单单的小白兔，
跑来跑去回头望。
衣服啊，还是新的好；
人啊，还是老朋友贴心。`, interpretation: `这首小诗来自汉代，是一位被抛弃的妇女在悲叹自己不如新欢。诗的开头用一只孤单的小白兔东奔西跑、不断回头张望的样子，来形容女主人被休弃后茫然无依、四处徘徊的凄凉心境。后来"衣不如新，人不如故"成了千古名句，常被用来劝诫人们珍惜老朋友、念旧情。它用最朴素的语言说出了最深的道理，所以才能流传两千多年，到现在还常被人们念叨呢！` }] },
  { id: 855, title: "董娇饶",
    author: "宋子侯",
    dynasty: "汉",
    category: "汉",
    summary: "洛阳城东路，桃李生路旁，花花自相对，叶叶自相当，春风东北起，花叶正低昂，不知力衰去，不见旧时芳",
    tags: "汉,经典",
    color: "#dc2626",
    sections:[    { id: 1, title: "董娇饶", original: `
洛阳城东路，
桃李生路旁，
花花自相对，
叶叶自相当，
春风东北起，
花叶正低昂，
不知力衰去，
不见旧时芳
`, translation: `洛阳城东边的路上，桃树李树长在路的两旁。一朵朵花自己相对开放，一片片叶子自己相互依傍。春风从东北方向吹过来，花儿和叶子随风上下飘荡。不知不觉花朵力气衰败、飘落而去，再也看不见从前那娇美的模样。`, interpretation: `这首汉代诗写的是洛阳城东路边上的桃李花。诗人用'花自相对''叶叶自相当'这样的句子，把花儿比作漂亮的姑娘董娇饶，她们曾经娇艳动人，可一阵春风吹过，花儿就凋零衰败了。这首诗用花开花落来感叹美好事物容易消逝，是中国较早的'花意象'诗。后来很多诗人写美人、写青春，都喜欢用花朵来打比方，比如'花谢花飞花满天'，就是从这种传统来的。短短几句，又整齐又有画面感，小朋友读起来像顺口溜一样好听呢。` }] },
  { id: 856, title: "定情诗",
    author: "繁钦",
    dynasty: "三国",
    category: "三国",
    summary: "我出东门游，邂逅承清尘，思君即幽房，侍寝执衣巾，时无桑中契，迫此路侧人，我既媚君姿，君亦悦我颜",
    tags: "三国,爱情",
    color: "#f97316",
    sections:[    { id: 1, title: "定情诗", original: `
我出东门游，
邂逅承清尘，
思君即幽房，
侍寝执衣巾，
时无桑中契，
迫此路侧人，
我既媚君姿，
君亦悦我颜
`, translation: `我走出东门去游玩，
没想到遇见了你，你风采迷人。
心里一直想着你，盼能和你在一起，
为你铺床叠被，伺候你的生活。
我们没有像桑中那样的约定，
只是路上偶然遇到的人。
我喜爱你的样子，
你也喜欢我的容颜。`, interpretation: `这首诗写于三国时期，是一首大胆直白的爱情诗。故事很简单：一位女子出门游玩，偶遇一位风度翩翩的男子，一见钟情，回家后日夜思念，恨不得马上嫁给他，为他打理生活起居。短短几句把少女的怦然心动写得真挚动人。最妙的是最后两句'我既媚君姿，君亦悦我颜'——你喜欢我的美，我也喜欢你的帅，两人互相倾慕，平等又直白，一点也不扭捏！这在讲究'女子要矜持'的古代非常难得。繁钦这首诗也被后人改编成经典古琴曲《陌上桑》，流传至今。` }] },
  { id: 857, title: "赠五官中郎将",
    author: "刘桢",
    dynasty: "三国",
    category: "三国",
    summary: "昔我从元后，整驾至南乡，过彼丰沛都，与君共翱翔，凉风吹沙砾，霜气何皑皑",
    tags: "三国,感怀",
    color: "#f97316",
    sections:[    { id: 1, title: "赠五官中郎将", original: `
昔我从元后，
整驾至南乡，
过彼丰沛都，
与君共翱翔，
凉风吹沙砾，
霜气何皑皑
`, translation: `从前我跟随皇上出征，坐着车驾一路向南。我们经过汉高祖的故乡丰邑和沛县，和你一起在天空中自由飞翔。凉飕飕的风吹起地上的沙石，寒冷的霜气多么洁白啊！`, interpretation: `这首诗写于三国时期，当时曹操的儿子曹丕担任五官中郎将，刘桢是他的属官。这首诗追忆了两人曾经随曹操南征，途经汉高祖刘邦的故乡丰县和沛县的情景。诗人用'凉风'、'沙砾'、'霜气'这些萧瑟的意象，营造出征战路途的苍凉氛围，也暗暗表达了对人生无常的感慨。'与君共翱翔'一句情谊深厚，成为后世吟咏友情的名句，让人感受到那段并肩同行的珍贵时光。` }] },
  { id: 858, title: "斗鸡诗",
    author: "刘桢",
    dynasty: "三国",
    category: "三国",
    summary: "丹鸡被华采，双距如锋芒，利爪探玉除，扬翘凌风飞，长距骋轻敌，枭雄独擅场",
    tags: "三国,经典",
    color: "#f97316",
    sections:[    { id: 1, title: "斗鸡诗", original: `
丹鸡被华采，
双距如锋芒，
利爪探玉除，
扬翘凌风飞，
长距骋轻敌，
枭雄独擅场
`, translation: `一只红色的斗鸡披着华丽的羽毛，它的两只脚爪就像锋利的刀刃一样。它用尖利的爪子在地上快速抓挠，扑扇着翅膀，就像迎着风飞起来一样。它伸出长长的脚距冲向弱小的对手，这位勇猛的英雄独自称霸战场。`, interpretation: `这首诗写于三国时期，那时候斗鸡是贵族和百姓都喜爱的娱乐活动。诗人刘桢用短短几句就把一只斗鸡写得威风凛凛。你看，他不写鸡的羽毛有多漂亮，而是直接抓住最厉害的部分——锋利的爪子、有力的翅膀，把斗鸡当作战士来描写。最有趣的是最后一句'枭雄独擅场'，明明是只鸡，却被比作英雄豪杰，独自在战场上称王。这种把动物当人写的办法，特别有气势，也让这首诗成了描写斗鸡的经典名篇。` }] },
  { id: 859, title: "酬范记室云",
    author: "何逊",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "林密户稍阴，草滋阶欲暗，风光蕊上轻，日色花中乱，相思不独欢，伫立空为叹",
    tags: "魏晋南北朝,写景",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "酬范记室云", original: `
林密户稍阴，
草滋阶欲暗，
风光蕊上轻，
日色花中乱，
相思不独欢，
伫立空为叹
`, translation: `树林太密了，屋门口都变得有点阴凉。
青草长得太旺了，台阶都快被遮得发暗了。
花瓣上轻轻飘过一阵微风，
阳光在花丛中晃来晃去，碎成一片金黄。
满心的思念啊，不只是我一个人觉得快乐，
我久久地站在这里，只能对着空气白白地叹息。`, interpretation: `这是南北朝时何逊写给朋友范云的一首应答诗。南北朝是个动荡的时代，但何逊特别擅长用细腻的笔触写身边的小风景，你看这首诗就像在用放大镜观察春天：阴凉的林荫、疯长的青草、花瓣上的微风、跳跃的阳光，全是生活中最普通、最温柔的画面，这就是他笔下最厉害的地方——用小景写心境。诗的后两句突然从美景转到思念：一个人站在花丛里，对美景却高兴不起来，因为身边没有朋友一起分享。这两句也让我们懂得：美好的事物，要有人一起欣赏才更快乐。` }] },
  { id: 860, title: "相送",
    author: "何逊",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "客心已百念，孤游重千里，江暗雨欲来，浪白风初起",
    tags: "魏晋南北朝,经典",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "相送", original: `
客心已百念，
孤游重千里，
江暗雨欲来，
浪白风初起
`, translation: `我这漂泊在外的游子啊，心里已经涌起了百种思念。独自一人踏上旅途，又要走上千里远。江面变得昏暗，雨好像马上就要落下来。浪花翻起白色，是风刚刚吹起的呀。`, interpretation: `这首诗是南朝诗人何逊送别友人时写的。南北朝时期，战争不断，亲友一别常常难以再见，所以送别诗特别多。诗中百念、千里写出了离人心中说不完的牵挂和路途的遥远。后两句不说人，直接写江上天气：江色变暗、雨快要来、浪白风起，用这些变化不定的景象，悄悄说出诗人心里七上八下的不安。这种把心情藏进风景里的写法，叫借景抒情，后来唐诗里用得非常多，比如王维、李白的送别诗都学过这一招呢！` }] },
  { id: 861, title: "山中",
    author: "庾信",
    dynasty: "南北朝",
    category: "南北朝",
    summary: "涧暗泉偏冷，岩深桂绝香，住中能不去，非独淮南王",
    tags: "魏晋南北朝,写景",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "山中", original: `
涧暗泉偏冷，
岩深桂绝香，
住中能不去，
非独淮南王
`, translation: `山涧幽暗，泉水格外清凉；
山岩深处，桂花的香气已消散。
我住在这山里，哪儿也不想去，
这可不是只有淮南王才做得到啊。`, interpretation: `这首诗出自南北朝诗人庾信，写的是他晚年隐居山中的生活。南北朝战乱频繁，庾信一生颠沛流离，晚年终于在山中找到安宁。诗中“涧暗”“岩深”写出山林的幽静，“泉冷”“桂绝”写出环境的清冷脱俗。最有趣的是最后两句——他说自己住在这里不愿离开，可不是说只有淮南王（传说中修仙炼丹的刘安）才能这样，我一个普通人也能享受这份清静！语言朴实却带点小幽默，是山水诗中的小精品，也让后人知道：宁静的快乐，平凡人也能拥有。` }] },
  { id: 862, title: "重别周尚书",
    author: "庾信",
    dynasty: "南北朝",
    category: "南北朝",
    summary: "阳关万里道，不见一人归，唯有河边雁，秋来南向飞",
    tags: "魏晋南北朝,经典",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "重别周尚书", original: `
阳关万里道，
不见一人归，
唯有河边雁，
秋来南向飞
`, translation: `通向阳关的路有万里那么长，
可是在这条路上，我却看不到一个回来的人。
只有黄河边上的大雁，
秋天一来，它们就成群结队地向南飞去。`, interpretation: `这首诗出自南北朝诗人庾信之手。当时南北对峙，战乱频繁，庾信被留在北方，心中十分思念家乡。诗中最动人的意象就是那群秋天南飞的大雁——大雁每年都能回到温暖的南方，可人却不能回家，形成了鲜明对比。“唯有”二字最让人心酸：路上空荡荡的，只剩大雁作伴。这首小诗语言朴素，却情真意切，短短二十个字写尽了漂泊在外的孤独与思乡之情，是古代思乡诗中的佳作。` }] },
  { id: 863, title: "拟咏怀·其二十六",
    author: "庾信",
    dynasty: "南北朝",
    category: "南北朝",
    summary: "萧条亭障远，凄惨风尘多，关门临白狄，城影入黄河，秋风别苏武，寒水送荆轲，谁言气盖世，晨起帐中歌",
    tags: "魏晋南北朝,感怀",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "拟咏怀·其二十六", original: `
萧条亭障远，
凄惨风尘多，
关门临白狄，
城影入黄河，
秋风别苏武，
寒水送荆轲，
谁言气盖世，
晨起帐中歌
`, translation: `边塞的亭障冷冷清清，远远望去一片萧瑟。风沙弥漫，天地间满是凄凉景象。关门遥遥对着西方的白狄，长城的影子倒映在黄河水中。秋风吹起，就像送别苏武远去；寒水奔流，恰如送别荆轲一去不返。都说项羽气盖世，可他不也曾在清晨帐中悲歌吗？`, interpretation: `这首诗写于南北朝时期，庾信被迫留在北方，心中充满对故国的思念和身不由己的痛苦。诗人站在边关眺望：亭障萧条、风尘凄苦、白狄远对、黄河映城，画面苍凉辽阔。他借苏武持节不屈、荆轲壮别易水、项羽垓下悲歌的典故，感叹英雄末路的悲凉，也暗喻自己空有气节却困于北地的无奈。这首诗善用历史人物抒发个人情怀，意境雄浑悲壮，对仗工整，是南北朝感怀诗中的名篇。` }] },
  { id: 864, title: "子夜四时歌·春歌",
    author: "佚名",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "春风动春心，流目瞩山林，山林多奇采，阳鸟吐清音",
    tags: "魏晋南北朝,民歌",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "子夜四时歌·春歌", original: `
春风动春心，
流目瞩山林，
山林多奇采，
阳鸟吐清音
`, translation: `春风轻轻吹呀吹，悄悄拨动了少女的心弦。她转动明亮的眼睛，望向远处的山林。山林里处处是美丽的景色，阳光下的鸟儿唱起了清脆悦耳的歌。`, interpretation: `这首小诗来自一千五百多年前南朝的一首民歌，是江南女子在春天里唱的情歌。短短二十个字，就像一幅会动的画：春风是主角，吹动了少女的春心，她忍不住张望山林，看见满山春色，还听见小鸟在阳光下欢唱。整首诗最妙的地方就是“动”和“流”两个动词——风在动，心在动，眼睛也在流动，读着读着，好像连空气都活了起来。这首民歌对后来唐诗影响很大，许多诗人都写过“春心”“阳鸟”这样的句子呢。` }] },
  { id: 865, title: "子夜歌·始欲识郎时",
    author: "佚名",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "始欲识郎时，两心望如一，理丝入残机，何悟不成匹",
    tags: "魏晋南北朝,民歌",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "子夜歌·始欲识郎时", original: `
始欲识郎时，
两心望如一，
理丝入残机，
何悟不成匹
`, translation: `刚开始想认识你的时候，咱俩的心都盼着能合到一起。我把丝线理好，放进织布机里想织成布，哪知道这丝线断了，怎么也织不成一匹完整的布呀。`, interpretation: `这首小诗来自一千五百多年前的南朝，是当时民间女子唱出的情歌。那时候的女孩心里有了喜欢的人，却不敢直接说出来，就借着织布这件事来打比方。你看，多有意思——她把两个人的感情比作织布，可丝线总是断，织不成整匹布，意思是说两个人总有些磕磕绊绊，没能顺顺利利地在一起。短短二十个字，用最平常的织布场景，说出了最让人心疼的想念，这种又甜又遗憾的调调，就是《子夜歌》最迷人的地方啦！` }] },
  { id: 866, title: "登幽州台歌",
    author: "陈子昂",
    dynasty: "唐",
    category: "唐",
    summary: "前不见古人后不见来者念天地之悠悠独怆然而涕下",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "登幽州台歌", original: `
前不见古人，
后不见来者。
念天地之悠悠，
独怆然而涕下
`, translation: `向前看，看不到古代那些贤明的君主；向后看，也看不到未来的圣贤。想到天地之间是多么辽阔悠久啊，我一个人孤零零地站在这里，止不住悲伤地流下眼泪。`, interpretation: `这首诗写于唐朝初年，陈子昂跟随武攸宜征战时遭到排挤，满怀失意地登上幽州台（今北京附近）。诗中没有华丽的辞藻，却用最简短有力的语言，写出了一个人站在天地间感到无比孤独和悲伤的感觉。"念天地之悠悠"是千古名句，想象自己面对无始无终的天地，怎能不感慨万千？后来很多诗人都受到这首诗的影响，比如杜甫的"无边落木萧萧下"就有类似的意境。它告诉我们：有时候感到渺小和孤独是正常的，连大诗人都会有这样的时刻呢。` }] },
  { id: 867, title: "送元二使安西",
    author: "王维",
    dynasty: "唐",
    category: "唐",
    summary: "渭城朝雨浥轻尘，客舍青青柳色新，劝君更尽一杯酒，西出阳关无故人",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "送元二使安西", original: `
渭城朝雨浥轻尘，
客舍青青柳色新，
劝君更尽一杯酒，
西出阳关无故人
`, translation: `清晨的细雨打湿了渭城的尘土，旅店旁的柳树被雨水洗过，显得格外青翠鲜亮。请你再干完这最后一杯酒吧！等你向西走出阳关以后，就再也没有老朋友了。`, interpretation: `这是王维送别好友去安西时写的一首送别诗，被称为《阳关三叠》，千百年来被传唱。诗里没有直接写伤心的眼泪，而是用"朝雨"和"柳色"这样清新的景象来铺垫——古人送别时会折柳相赠，柳树因此成了离别的象征。最后两句是千古名句，意思是：你再喝一杯吧，出了阳关就没朋友了！这份藏在酒杯里的牵挂，比哭哭啼啼更让人心酸。短短四句，景中有情，余味悠长，后来被编进乐府，成了古人告别时必唱的歌。` }] },
  { id: 868, title: "望庐山瀑布",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "日照香炉生紫烟，遥看瀑布挂前川，飞流直下三千尺，疑是银河落九天",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "望庐山瀑布", original: `
日照香炉生紫烟，
遥看瀑布挂前川，
飞流直下三千尺，
疑是银河落九天
`, translation: `阳光照在庐山的香炉峰上，升腾起紫色的云烟。远远望去，瀑布像一条白练挂在山前。瀑布从极高的地方飞奔直泻而下，足有三千尺，真让人怀疑是天上的银河从九重天落了下来。`, interpretation: `这首诗写于李白游庐山时。香炉峰是庐山的一座山峰，因为山顶常常云雾缭绕，像香炉里冒出的烟，所以叫这个名字。诗人远观瀑布，没有写近看的水花和声音，而是用夸张的手法说瀑布有三千尺高，像银河从天而降。这种写法叫“夸张”，是李白最擅长的。他用天上银河来比地上的瀑布，让整首诗又壮丽又充满想象，读起来就像在听一个超级英雄的故事。这首诗也成了中国人描写瀑布时最常引用的一首，连外国人都知道“飞流直下三千尺”这句名句呢！` }] },
  { id: 869, title: "峨眉山月歌",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "峨眉山月半轮秋，影入平羌江水流，夜发清溪向三峡，思君不见下渝州",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "峨眉山月歌", original: `
峨眉山月半轮秋，
影入平羌江水流，
夜发清溪向三峡，
思君不见下渝州
`, translation: `峨眉山上升起了半轮秋天的月亮，月影倒映在平羌江里，随着江水一起流淌。夜晚我从清溪出发，乘船前往三峡，心里一直想念着你却见不到面，只好带着这份思念顺流而下到渝州。`, interpretation: `这首诗写于李白年轻时离开四川老家的时候。峨眉山、平羌江、清溪、三峡、渝州，短短四句话里，李白一连用了五个地名，却一点都不觉得啰嗦，反而像在地图上画了一条漂亮的旅行路线，这就是这首诗最厉害的地方！诗中的月亮不只是月亮，它代表了故乡和思念，所以月影随水流，人也随月去，意境特别美。这首诗让后来的四川游子一想起家乡，就会想起峨眉山那轮清亮的秋月。` }] },
]
